// 设置错误处理器的通知桥接
const errorHandler = getErrorHandler();
errorHandler.setNotificationBridge(async (error: AppError) => {
  const notification = await mapErrorToNotification(error);
  if (!notification) {
    return;
  }

  try {
    await notifyAppEvent(notification);
  } catch (cause: unknown) {
    const fallbackError = notificationErrors.dispatchFailed(
      notification.message,
      { channel: notification.channel, title: notification.title },
      { cause }
    );
    await errorHandler.handle(fallbackError, { suppressNotifications: true });
  }
});

import type { I18nBinder, I18nBindingHandle, Messages } from '@i18n';
import { createIcon, Icons } from '@shared/utils/iconHelpers';
import {
  createContentActionRow,
  createContentLayoutElement,
  createContentSurfacePanel
} from '@ui/primitives/layout';
import { createCommentForm } from './commentForm';
import type { ReaderModeBehavior } from './dialogTypes';
import { getModifierLabel } from './dialogShortcuts';

export interface DialogPresenterBindings {
  applyText(
    element: HTMLElement,
    key: keyof Messages,
    fallback: string,
    binder: I18nBinder | null
  ): void;
  applyAttr(
    element: HTMLElement,
    attribute: string,
    datasetKey: string,
    key: keyof Messages,
    fallback: string,
    binder: I18nBinder | null
  ): void;
}

export interface DialogPresenterOptions {
  selectedText: string;
  initialComment: string;
  allowReaderMode: boolean;
  allowVideoMode: boolean;
  readerModeBehavior: ReaderModeBehavior;
  binder: I18nBinder | null;
  getFallback<Key extends keyof Messages>(key: Key): string;
  resolveAssetUrl(path: string): string;
  bindings: DialogPresenterBindings;
  registerI18nHandles(handles: I18nBindingHandle[]): void;
  onReader(): void;
  onVideo(): void;
  onCancel(): void;
  onConfirm(): void;
}

export interface DialogPresenterElements {
  content: HTMLDivElement;
  header: HTMLDivElement;
  textarea: HTMLTextAreaElement;
  hintElement: HTMLDivElement | null;
}

export function buildDialogPresenter(options: DialogPresenterOptions): DialogPresenterElements {
  const {
    selectedText,
    initialComment,
    allowReaderMode,
    allowVideoMode,
    readerModeBehavior,
    binder,
    getFallback,
    resolveAssetUrl,
    bindings,
    registerI18nHandles,
    onReader,
    onVideo,
    onCancel,
    onConfirm
  } = options;

  const content = createContentSurfacePanel({
    className: 'clipper-dialog-shell'
  });

  const header = createContentActionRow({
    className: 'clipper-dialog-header'
  });

  const title = document.createElement('h2');
  title.className = 'clipper-dialog-title';
  title.id = 'obsidian-clipper-title';

  const titleIcon = document.createElement('img');
  titleIcon.className = 'clipper-dialog-icon';
  titleIcon.alt = '';
  titleIcon.src = resolveAssetUrl('icons/allinob_icon_commentt.png');

  const titleLabel = document.createElement('span');
  bindings.applyText(titleLabel, 'clipDialogTitle', getFallback('clipDialogTitle'), binder);
  title.append(titleIcon, titleLabel);
  header.appendChild(title);
  content.appendChild(header);

  const instructions = document.createElement('p');
  instructions.id = 'clipper-dialog-instructions';
  instructions.className = 'clipper-sr-only';
  bindings.applyText(
    instructions,
    'clipDialogInstructions',
    getFallback('clipDialogInstructions'),
    binder
  );
  content.appendChild(instructions);

  const divider = createContentLayoutElement({ className: 'clipper-dialog-divider' });
  content.appendChild(divider);

  const commentForm = createCommentForm(
    {
      commentLabel: getFallback('commentLabel'),
      commentPlaceholder: getFallback('commentPlaceholder')
    },
    selectedText,
    initialComment,
    binder
  );
  registerI18nHandles(commentForm.handles);

  const textarea = commentForm.textarea;
  bindings.applyAttr(
    textarea,
    'aria-label',
    'i18nAriaLabel',
    'commentLabel',
    getFallback('commentLabel'),
    binder
  );
  const hintElement = commentForm.container.querySelector<HTMLDivElement>(
    '.clipper-comment-completed-hint'
  );
  content.appendChild(commentForm.container);

  content.setAttribute(
    'aria-describedby',
    [textarea.id, instructions.id].filter(Boolean).join(' ')
  );

  const actions = createContentActionRow({
    className: 'clipper-dialog-actions'
  });

  if (allowReaderMode) {
    const readerIcon = createIcon(Icons.ChevronRight, {
      size: 16,
      className: 'clipper-btn-icon'
    });
    readerIcon.setAttribute('aria-hidden', 'true');
    actions.appendChild(
      createGhostButton(
        binder,
        readerModeBehavior === 'append' ? 'addToReaderButton' : 'openReaderButton',
        readerModeBehavior === 'append'
          ? getFallback('addToReaderButton')
          : getFallback('openReaderButton'),
        readerIcon,
        bindings,
        onReader
      )
    );
  }

  if (allowVideoMode) {
    const videoIcon = createIcon(Icons.ChevronRight, {
      size: 16,
      className: 'clipper-btn-icon'
    });
    videoIcon.setAttribute('aria-hidden', 'true');
    actions.appendChild(
      createGhostButton(binder, 'openVideoModeButton', '进入视频模式', videoIcon, bindings, onVideo)
    );
  }

  const cancelButton = document.createElement('button');
  cancelButton.type = 'button';
  cancelButton.className = 'clipper-btn clipper-btn--secondary';
  bindings.applyText(cancelButton, 'cancelButton', getFallback('cancelButton'), binder);
  cancelButton.addEventListener('click', onCancel);
  actions.appendChild(cancelButton);

  const confirmButton = document.createElement('button');
  confirmButton.type = 'button';
  confirmButton.className = 'clipper-btn clipper-btn--primary';
  const confirmContent = document.createElement('span');
  confirmContent.className = 'clipper-btn-content';
  const confirmIcon = createIcon(Icons.Check, {
    size: 18,
    className: 'clipper-btn-icon'
  });
  confirmIcon.setAttribute('aria-hidden', 'true');
  const confirmLabel = document.createElement('span');
  confirmLabel.classList.add('btn-adaptive');
  bindings.applyText(confirmLabel, 'clipButton', getFallback('clipButton'), binder);
  confirmContent.append(confirmIcon, confirmLabel);
  confirmButton.appendChild(confirmContent);
  confirmButton.addEventListener('click', onConfirm);
  actions.appendChild(confirmButton);

  content.appendChild(actions);
  return {
    content,
    header,
    textarea,
    hintElement
  };
}

export function setInitialDialogPosition(container: HTMLDivElement): void {
  const viewportWidth = window.innerWidth || 800;
  const viewportHeight = window.innerHeight || 600;
  const dialogWidth = Math.min(600, viewportWidth * 0.9);
  const dialogHeight = Math.min(600, viewportHeight * 0.8);
  const initialX = (viewportWidth - dialogWidth) / 2;
  const initialY = (viewportHeight - dialogHeight) / 2;
  container.style.left = `${initialX}px`;
  container.style.top = `${initialY}px`;
  applyDialogPosition(container, 0, 0);
}

export function updateDialogPosition(
  container: HTMLElement,
  deltaX: number,
  deltaY: number,
  relative = false
): { x: number; y: number } {
  const currentX = Number(container.dataset.dx ?? 0);
  const currentY = Number(container.dataset.dy ?? 0);
  const nextX = relative ? currentX + deltaX : deltaX;
  const nextY = relative ? currentY + deltaY : deltaY;
  applyDialogPosition(container, nextX, nextY);
  return { x: nextX, y: nextY };
}

export function applyReadonlyTextareaPresentation(textarea: HTMLTextAreaElement): void {
  textarea.readOnly = true;
  textarea.style.opacity = '0.8';
  textarea.setAttribute('aria-readonly', 'true');
}

export function renderShortcutHint(
  hintElement: HTMLDivElement,
  messages: {
    header: string;
    doubleEnterLabel: string;
    doubleEnterAction: string;
    modifierAction: string;
    escapeAction: string;
  },
  platform?: string
): void {
  hintElement.hidden = false;
  hintElement.innerHTML = `
      ${messages.header}<br>
      <strong>${messages.doubleEnterLabel}</strong> ${messages.doubleEnterAction} |
      <strong>${getModifierLabel('hint', platform)}</strong> ${messages.modifierAction} |
      <strong>Esc</strong> ${messages.escapeAction}
    `;
}

export function addButtonShortcutHints(
  dialog: ParentNode,
  messages: {
    doubleEnterAction: string;
    modifierAction: string;
    escapeAction: string;
  }
): void {
  const buttons = dialog.querySelectorAll<HTMLButtonElement>(
    '.clipper-dialog-actions .clipper-btn'
  );
  buttons.forEach((element) => {
    if (element.parentElement?.classList.contains('clipper-btn-wrapper')) {
      return;
    }

    let hintText = '';
    if (element.classList.contains('clipper-btn--ghost')) {
      hintText = messages.doubleEnterAction;
    } else if (element.classList.contains('clipper-btn--primary')) {
      hintText = messages.modifierAction;
    } else if (element.classList.contains('clipper-btn--secondary')) {
      hintText = messages.escapeAction;
    }

    if (!hintText) {
      return;
    }

    wrapButtonWithHint(element, hintText);
  });
}

function applyDialogPosition(container: HTMLElement, x: number, y: number): void {
  container.dataset.dx = String(x);
  container.dataset.dy = String(y);
  container.style.transform = `translate(${x}px, ${y}px)`;
}

function wrapButtonWithHint(element: HTMLButtonElement, hintText: string): void {
  const wrapper = document.createElement('div');
  wrapper.className = 'clipper-btn-wrapper';
  wrapper.style.display = 'flex';
  wrapper.style.flexDirection = 'column';
  wrapper.style.alignItems = 'center';
  wrapper.style.gap = '4px';

  const parent = element.parentElement;
  if (!parent) {
    return;
  }

  parent.insertBefore(wrapper, element);
  wrapper.appendChild(element);

  const hint = document.createElement('div');
  hint.className = 'clipper-shortcut-hint';
  hint.textContent = hintText;
  hint.style.fontSize = '10px';
  hint.style.color = 'var(--accent-solid, #8B5CF6)';
  hint.style.textAlign = 'center';
  hint.style.fontWeight = '500';
  hint.style.opacity = '0.8';
  hint.style.whiteSpace = 'nowrap';
  wrapper.appendChild(hint);
}

function createGhostButton(
  binder: I18nBinder | null,
  messageKey: keyof Messages,
  fallback: string,
  icon: SVGElement,
  bindings: DialogPresenterBindings,
  onClick: () => void
): HTMLButtonElement {
  const button = document.createElement('button');
  button.type = 'button';
  button.className = 'clipper-btn clipper-btn--ghost';

  const content = document.createElement('span');
  content.className = 'clipper-btn-content';

  icon.classList.add('clipper-btn-icon');
  icon.setAttribute('aria-hidden', 'true');

  const label = document.createElement('span');
  bindings.applyText(label, messageKey, fallback, binder);

  content.append(icon, label);
  button.appendChild(content);
  button.addEventListener('click', onClick);
  return button;
}

import { type ClipperDialogOptions } from '../components/dialog';
import { createClipperDialog } from '../components/dialogFactory';
import type {
  ClipPromptGateway,
  ClipPromptRequest,
  ClipPromptResponse
} from '../application/clipPromptGateway';
import type { PopupCoordinator } from '../../runtime/popupCoordinator';
import { resolveContentPopupCoordinator } from '../../runtime/popupCoordinatorAccess';

class ClipperDialogPromptGateway implements ClipPromptGateway {
  async requestSelectionAction(request: ClipPromptRequest): Promise<ClipPromptResponse> {
    const dialog = createClipperDialog();
    const baseOptions: ClipperDialogOptions = {
      allowReaderMode: request.allowReaderMode,
      readerModeBehavior: request.readerModeBehavior
    };

    const withVideoOption =
      request.allowVideoMode === undefined
        ? baseOptions
        : { ...baseOptions, allowVideoMode: request.allowVideoMode };

    const dialogOptions =
      request.initialComment === undefined
        ? withVideoOption
        : { ...withVideoOption, initialComment: request.initialComment };
    const popupCoordinator = resolveContentPopupCoordinator();

    const result = await dialog.show(request.selectedText, {
      ...dialogOptions,
      ...(popupCoordinator ? { dialogRegistry: popupCoordinator } : {})
    });
    return {
      action: result.action,
      comment: result.comment ?? '',
      ...(result.destination ? { destination: result.destination } : {})
    };
  }
}

export function createClipperDialogPromptGateway(): ClipPromptGateway {
  return new ClipperDialogPromptGateway();
}

import { buildChatMarkdown } from '../formatters/markdown';
import { chatHtmlToMarkdown } from '../../third_party/ai-chat-exporter/parse';
import { formatDateTime } from '../clipper/utils/datetime';
import { isAIChat } from '../detect';
import type { StoredOptions, OptionsState } from '../../shared/types/options';
import type { ContentExtractor, ExtractionContext } from './types';
import type { OptionsRepository } from '../../shared/interfaces/optionsRepository';
import type { IOptionsRepository } from '../../shared/repositories/IOptionsRepository';
import type { ParsedMessage } from '../../third_party/ai-chat-exporter/types';

interface OptionsProvider {
  get(): Promise<StoredOptions>;
  reset(): void;
}

export interface AIChatExtractorDeps {
  optionsRepository?: OptionsRepository | IOptionsRepository;
  optionsProvider?: OptionsProvider;
  detectPlatform(url: string): string;
  now(): Date;
}

interface ResolvedAIChatExtractorDeps {
  optionsProvider: OptionsProvider;
  detectPlatform(url: string): string;
  now(): Date;
}

function isLegacyOptionsRepository(
  repository: OptionsRepository | IOptionsRepository
): repository is OptionsRepository {
  return 'load' in repository && typeof repository.load === 'function';
}

function createOptionsProviderFromRepository(
  repository: OptionsRepository | IOptionsRepository
): OptionsProvider {
  let cached: StoredOptions | undefined;
  let pending: Promise<StoredOptions> | null = null;
  let unsubscribe: (() => void) | null = null;

  const ensureSubscription = () => {
    if (unsubscribe) {
      return;
    }
    if (isLegacyOptionsRepository(repository)) {
      unsubscribe = repository.subscribe((value) => {
        cached = value;
      });
      return;
    }

    unsubscribe = repository.onChange((value) => {
      cached = value as StoredOptions;
    });
  };

  return {
    async get(): Promise<StoredOptions> {
      ensureSubscription();

      if (cached) {
        return cached;
      }

      if (pending === null) {
        pending = (isLegacyOptionsRepository(repository) ? repository.load() : repository.get())
          .then((value) => {
            cached = value;
            return value;
          })
          .finally(() => {
            pending = null;
          });
      }

      return pending;
    },
    reset(): void {
      cached = undefined;
      pending = null;
      unsubscribe?.();
      unsubscribe = null;
    }
  };
}

function createEmptyOptionsProvider(): OptionsProvider {
  return {
    get: async () => ({}) as StoredOptions,
    reset: () => undefined
  };
}

function defaultDetectPlatform(url: string): string {
  if (/(chatgpt|chat\.openai\.com)/.test(url)) return 'chatgpt';
  if (/claude/.test(url)) return 'claude';
  if (/gemini/.test(url)) return 'gemini';
  if (/copilot/.test(url)) return 'copilot';
  if (/tongyi/.test(url)) return 'tongyi';
  if (/deepseek/.test(url)) return 'deepseek';
  if (/kimi|moonshot/.test(url)) return 'kimi';
  if (/doubao/.test(url)) return 'doubao';
  if (/monica/.test(url)) return 'monica';
  if (/perplexity/.test(url)) return 'perplexity';
  return 'chat';
}

interface ChatMarkdownMessage {
  id: string;
  role: ParsedMessage['role'];
  text: string;
  timestamp?: string;
}

interface ChatMarkdownOptions {
  includeTimestamps?: boolean;
  userName?: string;
}

interface ChatMarkdownInput {
  title: string;
  platform: string;
  url: string;
  messages: ChatMarkdownMessage[];
  model?: string;
  createdAt?: string;
  options: ChatMarkdownOptions;
}

function normalizeMessages(messages: ParsedMessage[]): ChatMarkdownMessage[] {
  return messages.map((message, index) => {
    const text =
      message.md ?? (message.html ? chatHtmlToMarkdown(message.html) : (message.text ?? ''));
    const normalized: ChatMarkdownMessage = {
      id: message.id || `m${index}`,
      role: message.role,
      text
    };

    if (message.timestamp) {
      normalized.timestamp = message.timestamp;
    }

    return normalized;
  });
}

export const createAIChatExtractor = (deps?: Partial<AIChatExtractorDeps>): ContentExtractor => {
  const optionsProvider =
    deps?.optionsProvider ??
    (deps?.optionsRepository
      ? createOptionsProviderFromRepository(deps.optionsRepository)
      : createEmptyOptionsProvider());

  const resolvedDeps: ResolvedAIChatExtractorDeps = {
    optionsProvider,
    detectPlatform: deps?.detectPlatform ?? defaultDetectPlatform,
    now: deps?.now ?? (() => new Date())
  };

  const extract = async ({ document, url }: ExtractionContext) => {
    const platform = resolvedDeps.detectPlatform(url);
    const storedOptions = await resolvedDeps.optionsProvider.get();
    const options = storedOptions as OptionsState;

    const parseConfig = {
      deepResearch: {
        pureMode: options?.deepResearch?.pureMode || false
      }
    };

    const { parseChatDOMAsync } = await import(
      '../../third_party/ai-chat-exporter/runtimeRegistry'
    );
    const { title, messages, assets, model, createdAt } = await parseChatDOMAsync(
      platform,
      document,
      parseConfig
    );
    const aiChatOptions: ChatMarkdownOptions = {
      includeTimestamps: options?.aiChat?.includeTimestamps ?? false,
      userName: options?.aiChat?.userName || 'USER'
    };
    const normalizedMessages = normalizeMessages(messages);

    const baseInput: ChatMarkdownInput = {
      title,
      platform,
      url,
      messages: normalizedMessages,
      options: aiChatOptions
    };

    const chatMarkdownInput: ChatMarkdownInput = {
      ...baseInput,
      ...(model !== undefined ? { model } : {}),
      ...(createdAt !== undefined ? { createdAt } : {})
    };

    const markdown = buildChatMarkdown(chatMarkdownInput);

    return {
      type: 'ai_chat' as const,
      title,
      markdown,
      assets,
      meta: {
        url,
        platform,
        model,
        messageCount: normalizedMessages.length,
        ...(createdAt ? { createdAt } : {}),
        clippedAtISO: formatDateTime(resolvedDeps.now())
      }
    };
  };

  return {
    id: 'ai.chat',
    priority: 200,
    canHandle(context: ExtractionContext): Promise<boolean> {
      return Promise.resolve(isAIChat(context.url, context.document));
    },
    extract
  };
};

export async function extractAIChat(
  doc: Document,
  url: string,
  deps?: Partial<
    Pick<AIChatExtractorDeps, 'optionsRepository' | 'optionsProvider' | 'detectPlatform' | 'now'>
  >
) {
  return createAIChatExtractor(deps).extract({ document: doc, url });
}

