    document,
    window,
    runtime: platform.runtime
  });
  const showSupportProgress = (progress: SupportProgressUpdate): void => {
    const variant = progress.variant ?? 'progress';
    const status = variant === 'progress' ? 'progress' : variant;
    void supportPrompt.show({
      status,
      progress: {
        ...progress,
        variant
      }
    });
  };
  const createReaderSession = createLazyReaderSessionFactory({
    document,
    optionsRepository: primaryOptionsRepository,
    storage: platform.storage,
    messaging: platform.messaging,
    runtime: platform.runtime,
    promptGateway: clipPromptGateway,
    showSupportProgress
  });
  const createVideoSession = createLazyVideoSessionFactory({
    document,
    optionsRepository: primaryOptionsRepository,
    storage: platform.storage,
    messaging: platform.messaging,
    runtime: platform.runtime,
    showSupportProgress
  });
  const selectionController = createSelectionController({
    prompt: clipPromptGateway,
    optionsRepository: primaryOptionsRepository,
    createReaderSession,
    createVideoSession
  });
  const extractorRegistry = createLazyExtractorRegistry(primaryOptionsRepository);
  const selectionTracker = createContentSelectionTracker({
    document,
    window,
    enablePlatformShadowSelection: /(^|\.)bilibili\.com$/i.test(window.location.hostname),
    getLastSelectionSnapshot: () => runtimeState.getLastSelectionSnapshot(),
    setLastSelectionSnapshot: (snapshot) => {
      runtimeState.setLastSelectionSnapshot(snapshot);
    }
  });
  // composition below moved to runtime/bootstrapRuntime

  void runtimeState.refreshFragmentConfig();
  void initializeVideoPromptOnDemand(
    {
      optionsRepository: primaryOptionsRepository,
      storage: platform.storage,
      runtime: platform.runtime,
      showSupportProgress
    },
    window.location.href
  );

  const runtime = createContentRuntime({
    document,
    window,
    messaging,
    runtimeState,
    selectionTracker,
    selectionController,
    extractorRegistry,
    showSupportProgress,
    createRouter: (runClip) =>
      createContentMessageRouter({
        document,
        window,
        messaging,
        supportPrompt,
        localVaultPermissionPrompt,
        setClipMode: (mode) => runtimeState.setClipMode(mode),
        runClip,
        selectionController,
        createVideoSession: () => createVideoSession(document),
        isVideoSessionActive: () => isVideoSessionActive(document),
        getVideoSession: () => getVideoSession<ReturnType<typeof createVideoSession>>(document),
        resolveActiveSelection: () => selectionTracker.resolveActiveSelection(),
        restoreSelectionFromSnapshot: (snapshot) =>
          selectionTracker.restoreSelectionFromSnapshot(snapshot),
        getLastSelectionSnapshot: () => runtimeState.getLastSelectionSnapshot(),
        clearLastSelectionSnapshot: () => runtimeState.setLastSelectionSnapshot(null)
      })
  });
  runtime.start();
  window.addEventListener(
    'pagehide',
    () => {
      stopRuntimeThemeSync();
      runtime.stop();
    },
    { passive: true }
  );
}

import type { ClipPromptGateway } from '../clipper/application/clipPromptGateway';
import { DEFAULT_FRAGMENT_CONFIG } from '../clipper/services/fragmentConfig';
import { ADD_HIGHLIGHT_EVENT } from './constants';
import { handleReaderKeydown, isNodeInsideReaderUi } from './sessionDom';
import { ReaderSessionState, resolveReadingConfig } from './sessionState';
import type { ReaderBootstrapHighlight } from './types';
import type { ExternalHighlightPayload } from './types';
import type { ReaderSelectionPayload } from './services/selectionController';
import type { ReaderHighlightManager, ReaderHighlightRecord } from './services/highlightManager';
import type { ReaderPanelCoordinator } from './panelCoordinator';
import type { ReaderSelectionController } from './services/selectionController';
import type { ReaderEnvironmentController } from './environmentController';
import type { ReaderSessionLifecycle } from './sessionLifecycle';
import type { ReadingSessionOptions } from '../../shared/types/options';
import {
  clearReaderSession,
  isReaderSessionActive,
  registerReaderSession
} from '../runtime/contentSessionRegistry';
import { clearHighlightThemeState } from '../shared/highlightThemeState';
import { ContentExportDestinationState } from '../shared/exportDestinationState';
import type { ClipPayload } from '../../shared/types';
import type { ReaderSessionDependencies as FullReaderSessionDependencies } from './sessionTypes';
import {
  addReaderHighlightFromRange,
  cancelReaderSession,
  finishReaderSession,
  focusReaderHighlight,
  handleReaderSessionMouseUp,
  handleReaderSessionSelection,
  ingestExternalReaderHighlight,
  removeReaderHighlight,
  submitReaderHighlightEdit
} from './sessionOperations';

export type { ReaderSessionDependencies } from './sessionTypes';

export class ReaderSession {
  private readonly state = new ReaderSessionState();
  private readonly dependencies: FullReaderSessionDependencies;
  private readonly highlightManager: ReaderHighlightManager;
  private readonly panelCoordinator: ReaderPanelCoordinator;
  private readonly selectionController: ReaderSelectionController;
  private readonly environment: ReaderEnvironmentController;
  private readonly lifecycle: ReaderSessionLifecycle;
  private readonly destinationState: ContentExportDestinationState;

  private get operationContext() {
    return {
      session: this,
      doc: this.doc,
      url: this.url,
      clipPrompt: this.clipPrompt,
      state: this.state,
      highlightManager: this.highlightManager,
      panelCoordinator: this.panelCoordinator,
      lifecycle: this.lifecycle,
      dependencies: this.dependencies,
      getExportDestinationMetadata: () => this.destinationState.metadata
    };
  }

  constructor(
    private readonly doc: Document,
    private readonly url: string,
    private readonly clipPrompt: ClipPromptGateway,
    dependencies: FullReaderSessionDependencies
  ) {
    this.dependencies = dependencies;
    this.highlightManager = this.dependencies.createHighlightManager(this.doc);
    this.panelCoordinator = this.dependencies.createPanelCoordinator({
      viewFactory: this.dependencies.viewFactory,
      callbacks: {
        onFinish: () => this.finish(),
        onCancel: () => this.cancel(),
        onSelectDestination: (id) => this.selectDestination(id),
        onDeleteHighlight: (id) => this.removeHighlightById(id),
        onSubmitHighlightEdit: (id, comment) => this.submitHighlightEdit(id, comment),
        onFocusHighlight: (id) => this.focusHighlight(id)
      },
      reconstructText: (highlight) => this.highlightManager.reconstructText(highlight)
    });
    this.selectionController = this.dependencies.createSelectionController({
      doc: this.doc,
      fragmentConfig: DEFAULT_FRAGMENT_CONFIG,
      canHandleSelection: () => !this.state.handlingSelection && !this.state.exporting,
      isNodeInsideUi: (node) =>
        isNodeInsideReaderUi(node, this.panelCoordinator.getElement(), this.doc),
      onSelectionReady: (payload) => {
        void this.handleSelection(payload);
      }
    });
    this.environment = this.dependencies.createEnvironmentController(
      {
        doc: this.doc,
        storage: this.dependencies.storage,
        optionsRepository: this.dependencies.optionsRepository
      },
      {
        onMessagesUpdate: (messages) => {
          this.state.messages = messages;
          this.panelCoordinator.updateMessages(messages, this.state.highlights);
        },
        onFragmentConfigUpdate: (config) => {
          this.selectionController.updateFragmentConfig(config);
        }
      }
    );
    this.lifecycle = this.dependencies.createLifecycle(
      {
        doc: this.doc,
        selectionController: this.selectionController,
        panelCoordinator: this.panelCoordinator,
        environment: this.environment,
        externalHighlightEvent: ADD_HIGHLIGHT_EVENT
      },
      {
        onSelection: (_payload) => {
          // Selection flow is already owned by the selection controller wiring.
        },
        onExternalHighlight: (payload) => this.ingestExternalHighlightPayload(payload),
        onKeydown: (event) => {
          handleReaderKeydown(event, {
            isPanelEditing: () => this.panelCoordinator.isEditing(),
            onCancel: () => this.cancel(),
            onFinish: () => this.finish()
          });
        }
      }
    );
    this.destinationState = new ContentExportDestinationState(
      this.dependencies.optionsRepository,
      () => this.createDestinationPayload(),
      this.dependencies.optionsPageUrl
    );
  }

  async initialize(
    initialHighlights?: ReaderBootstrapHighlight | ReaderBootstrapHighlight[]
  ): Promise<void> {
    await this.start(initialHighlights);
  }

  destroy(): void {
    this.cancel();
  }

  __setTestHighlights(
    records: Array<{
      id: string;
      selectedHtml: string;
      selectedText: string;
      comment: string;
      fragmentUrl: string;
      wrapper: HTMLElement;
    }>
  ): void {
    this.state.highlights = records.map((record) => ({
      id: record.id,
      selectedHtml: record.selectedHtml,
      selectedText: record.selectedText,
      comment: record.comment,
      fragmentUrl: record.fragmentUrl,
      wrapper: record.wrapper,
      wrapperSegments: [record.wrapper],
      createdAt: Date.now()
    }));
    this.syncHighlightsUi();
  }

  get __testHighlights(): Array<{
    id: string;
    selectedHtml: string;
    selectedText: string;
    comment: string;
    fragmentUrl: string;
    wrapper: HTMLElement;
  }> {
    return this.state.highlights;
  }

  async start(
    initialHighlights?: ReaderBootstrapHighlight | ReaderBootstrapHighlight[]
  ): Promise<void> {
    if (isReaderSessionActive(this.doc)) {
      return;
    }

    registerReaderSession(this, this.doc);

    try {
      await this.lifecycle.start();
      this.applyInitialDestination(initialHighlights);
      await this.refreshDestinationPreview();
      this.applyReadingConfig(await this.loadReadingConfig());
      this.watchReadingConfig();
      this.bootstrapHighlights(initialHighlights);
      this.panelCoordinator.refreshHint(this.state.highlights.length);
    } catch (error) {
      clearReaderSession(this, this.doc);
      throw error;
    }
  }

  private bootstrapHighlights(
    initialHighlights?: ReaderBootstrapHighlight | ReaderBootstrapHighlight[]
  ): void {
    const bootHighlights = initialHighlights
      ? Array.isArray(initialHighlights)
        ? initialHighlights
        : [initialHighlights]
      : [];

    for (const highlight of bootHighlights) {
      try {
        this.addHighlightFromRange(
          highlight.range,
          highlight.selectedHtml,
          highlight.selectedText,
          highlight.comment
        );
      } catch (error) {
        console.error('[ReaderSession] Failed to add initial highlight:', error);
      }
    }
  }

  private applyInitialDestination(
    initialHighlights?: ReaderBootstrapHighlight | ReaderBootstrapHighlight[]
  ): void {
    const bootHighlights = initialHighlights
      ? Array.isArray(initialHighlights)
        ? initialHighlights
        : [initialHighlights]
      : [];
    const initialDestination = bootHighlights.find(
      (highlight) => highlight.destination
    )?.destination;
    this.destinationState.applyMetadata(initialDestination);
  }

  private async loadReadingConfig(): Promise<ReadingSessionOptions> {
    try {
      return resolveReadingConfig(await this.dependencies.readerRepository.getReadingConfig());
    } catch (error) {
      console.warn('[ReaderSession] Failed to load reading config, using defaults:', error);
      return resolveReadingConfig();
    }
  }

  private watchReadingConfig(): void {
    this.state.stopReadingConfigWatcher?.();
    this.state.stopReadingConfigWatcher = this.dependencies.readerRepository.onConfigChange(
      (config) => {
        this.applyReadingConfig(resolveReadingConfig(config));
      }
    );
  }

  private applyReadingConfig(config: ReturnType<typeof resolveReadingConfig>): void {
    this.state.readingConfig = config;
    this.highlightManager.applyTheme(config.highlightTheme);
  }

  private async handleSelection(payload: ReaderSelectionPayload): Promise<void> {
    await handleReaderSessionSelection(this.operationContext, payload);
  }

  private async handleMouseUp(event: MouseEvent): Promise<void> {
    await handleReaderSessionMouseUp(this.operationContext, event);
  }

  private addHighlightFromRange(
    range: Range,
    selectedHtml: string,
    selectedText: string,
    comment: string
  ): void {
    addReaderHighlightFromRange(this.operationContext, range, selectedHtml, selectedText, comment);
  }

  ingestExternalHighlight(
    range: Range,
    selectedHtml: string,
    selectedText: string,
    comment: string
  ): void {
    this.ingestExternalHighlightPayload({ range, selectedHtml, selectedText, comment });
  }

  private ingestExternalHighlightPayload(payload: ExternalHighlightPayload): void {
    ingestExternalReaderHighlight(this.operationContext, payload);
  }

  private syncHighlightsUi(): void {
    this.highlightManager.sortByDocumentOrder(this.state.highlights);
    this.panelCoordinator.updateHighlights(this.state.highlights);
  }

  private async finish(): Promise<void> {
    await finishReaderSession(
      this.operationContext,
      () => this.loadReadingConfig(),
      (config) => this.applyReadingConfig(config)
    );
  }

  private async refreshDestinationPreview(): Promise<void> {
    const preview = await this.destinationState.refresh();
    this.panelCoordinator.updateDestination(preview);
  }

  private async selectDestination(id: string): Promise<void> {
    this.destinationState.select(id);
    await this.refreshDestinationPreview();
  }

  private createDestinationPayload(): ClipPayload {
    const parsedUrl = this.parseCurrentUrl();
    const title = this.doc.title || parsedUrl?.hostname || 'Untitled';
    const domain = parsedUrl?.hostname ?? '';
    const markdown = this.state.highlights
      .map((highlight) => this.highlightManager.reconstructText(highlight))
      .join('\n\n');
    return {
      markdown: markdown || title,
      title,
      type: 'clipper',
      meta: {
        url: this.url,
        sourceUrl: this.url,
        resolvedUrl: this.url,
        ...(domain ? { domain } : {}),
        readerMode: true
      }
    };
  }

  private parseCurrentUrl(): URL | null {
    try {
      return new URL(this.url);
    } catch {
      return null;
    }
  }

  private cancel(): void {
    cancelReaderSession(this.operationContext);
  }

  private cleanup(): void {
    this.lifecycle.cleanup();
    this.state.stopReadingConfigWatcher?.();
    this.state.stopReadingConfigWatcher = null;

    for (const highlight of this.state.highlights) {
      this.highlightManager.unwrapHighlight(highlight);
    }
    this.state.highlights = [];

    clearReaderSession(this, this.doc);
    this.state.exporting = false;
    this.state.handlingSelection = false;
    clearHighlightThemeState(this.doc);

    if (this.state.highlightFocusTimeout !== null) {
      this.doc.defaultView?.clearTimeout(this.state.highlightFocusTimeout);
      this.state.highlightFocusTimeout = null;
    }

    this.doc.defaultView?.getSelection()?.removeAllRanges();
  }

  private focusHighlight(id: string): void {
    focusReaderHighlight(this.operationContext, id);
  }

  private removeHighlightById(id: string): void {
    removeReaderHighlight(this.operationContext, id);
  }

  private submitHighlightEdit(id: string, nextComment: string): void {
    submitReaderHighlightEdit(this.operationContext, id, nextComment);
  }

  private findHighlight(id: string): ReaderHighlightRecord | undefined {
    return this.state.highlights.find((highlight) => highlight.id === id);
  }
}

import type { ClipPromptGateway } from '../clipper/application/clipPromptGateway';
import { generateTextFragmentUrl } from '../clipper/utils/textFragment';
import { createReaderHighlightId, type ReaderSessionState } from './sessionState';
import type { ReaderSelectionPayload } from './services/selectionController';
import type { ReaderHighlightManager, ReaderHighlightRecord } from './services/highlightManager';
import type { ReaderPanelCoordinator } from './panelCoordinator';
import type { ReaderSessionDependencies } from './sessionTypes';
import type { ReaderSessionLifecycle } from './sessionLifecycle';
import type { ExportDestinationMetadata } from '@shared/exportDestination';
import { isNodeInsideReaderUi } from './sessionDom';
import { clearReaderSession } from '../runtime/contentSessionRegistry';
import { clearHighlightThemeState } from '../shared/highlightThemeState';

interface ReaderSessionOperationContext {
  session: object;
  doc: Document;
  url: string;
  clipPrompt?: ClipPromptGateway;
  state: ReaderSessionState;
  highlightManager: ReaderHighlightManager;
  panelCoordinator: ReaderPanelCoordinator;
  lifecycle: ReaderSessionLifecycle;
  dependencies: ReaderSessionDependencies;
  getExportDestinationMetadata?: () => ExportDestinationMetadata | undefined;
}

export async function handleReaderSessionSelection(
  context: ReaderSessionOperationContext,
  payload: ReaderSelectionPayload
): Promise<void> {
  context.state.handlingSelection = true;

  try {
    addReaderHighlightFromRange(
      context,
      payload.range,
      payload.selectedHtml,
      payload.selectedText,
      ''
    );
    context.doc.defaultView?.getSelection()?.removeAllRanges();
  } catch (error) {
    console.error('[ReaderSession] Failed to capture selection:', error);
    context.panelCoordinator.applyHint('selectionFailure', context.state.highlights.length);
  } finally {
    context.state.handlingSelection = false;
  }
}

export async function handleReaderSessionMouseUp(
  context: ReaderSessionOperationContext,
  event: MouseEvent
): Promise<void> {
  if (context.state.handlingSelection || context.state.exporting || event.button !== 0) {
    return;
  }

  const selection = context.doc.defaultView?.getSelection() ?? window.getSelection();
  if (!selection || selection.rangeCount === 0 || selection.isCollapsed) {
    return;
  }

  if (
    isNodeInsideReaderUi(
      selection.anchorNode,
      context.panelCoordinator.getElement(),
      context.doc
    ) ||
    isNodeInsideReaderUi(selection.focusNode, context.panelCoordinator.getElement(), context.doc)
  ) {
    selection.removeAllRanges();
    return;
  }

  const selectedText = selection.toString().trim();
  if (!selectedText) {
    selection.removeAllRanges();
    return;
  }

  const range = selection.getRangeAt(0).cloneRange();
  const container = context.doc.createElement('div');
  container.appendChild(range.cloneContents());

  await handleReaderSessionSelection(context, {
    range,
    selectedHtml: container.innerHTML,
    selectedText,
    event
  });
}

export function addReaderHighlightFromRange(
  context: ReaderSessionOperationContext,
  range: Range,
  selectedHtml: string,
  selectedText: string,
  comment: string
): void {
  const id = createReaderHighlightId();
  const fragmentUrl = generateTextFragmentUrl(context.url, selectedText);
  const highlight =
    context.highlightManager.createHighlight({
      id,
      range,
      selectedHtml,
      selectedText,
      comment,
      fragmentUrl
    }) ??
    createDetachedReaderHighlight(
      context.doc,
      id,
      selectedHtml,
      selectedText,
      comment,
      fragmentUrl
    );
  context.state.highlights.push(highlight);
  syncReaderHighlightsUi(context);
  context.panelCoordinator.applyHint('panel', context.state.highlights.length);
}

export function ingestExternalReaderHighlight(
  context: ReaderSessionOperationContext,
  payload: { range: Range; selectedHtml: string; selectedText: string; comment: string }
): void {
  addReaderHighlightFromRange(
    context,
    payload.range,
    payload.selectedHtml,
    payload.selectedText,
    payload.comment
  );
  context.doc.defaultView?.getSelection()?.removeAllRanges();
}

export async function finishReaderSession(
  context: ReaderSessionOperationContext,
  loadReadingConfig: () => Promise<
    ReturnType<typeof import('./sessionState').resolveReadingConfig>
  >,
  applyReadingConfig: (
    config: ReturnType<typeof import('./sessionState').resolveReadingConfig>
  ) => void
): Promise<void> {
  if (context.state.exporting) {
    return;
  }

  if (!context.state.highlights.length) {
    context.panelCoordinator.applyHint('noHighlights', 0);
    return;
  }

  context.state.exporting = true;
  context.panelCoordinator.applyHint('exporting', context.state.highlights.length);
  context.dependencies.showSupportProgress?.({
    value: 10,
    label: '正在准备阅读导出'
  });

  try {
    applyReadingConfig(await loadReadingConfig());
    context.dependencies.showSupportProgress?.({
      value: 24,
      label: '正在整理阅读标注'
    });
    const highlights = context.dependencies.exporter.prepareHighlights(
      context.state.highlights,
      context.highlightManager
    );
    const pageTitle = context.doc.title || new URL(context.url).hostname;
    const documentClone =
      context.state.readingConfig.exportMode === 'full'
        ? (context.doc.cloneNode(true) as Document)
        : undefined;

    if (documentClone) {
      context.dependencies.exporter.applyTokens(documentClone, highlights);
    }

    context.dependencies.showSupportProgress?.({
      value: 32,
      label: '正在生成阅读笔记'
    });
    const payload = await context.dependencies.exporter.buildMarkdown({
      mode: context.state.readingConfig.exportMode,
      pageTitle,
      pageUrl: context.url,
      highlights,
      ...(documentClone !== undefined && { documentClone })
    });
    const exportDestination = context.getExportDestinationMetadata?.();
    if (exportDestination) {
      payload.meta = {
        ...payload.meta,
        exportDestination
      };
    }

    context.dependencies.showSupportProgress?.({
      value: 36,
      label: '正在发送到 Obsidian'
    });
    await context.dependencies.dispatchClipResult(payload);
    cleanupReaderSession(context);
  } catch (error) {
    console.error('[ReaderSession] Export failed:', error);
    context.dependencies.showSupportProgress?.({
      value: 100,
      label: '发送失败',
      variant: 'failure'
    });
    context.panelCoordinator.applyHint('failure', context.state.highlights.length);
    context.state.exporting = false;
  }
}

export function cancelReaderSession(context: ReaderSessionOperationContext): void {
  if (context.state.exporting) {
    return;
  }
  cleanupReaderSession(context);
}

export function cleanupReaderSession(context: ReaderSessionOperationContext): void {
  context.lifecycle.cleanup();
  context.state.stopReadingConfigWatcher?.();
  context.state.stopReadingConfigWatcher = null;

  for (const highlight of context.state.highlights) {
    context.highlightManager.unwrapHighlight(highlight);
  }
  context.state.highlights = [];

  clearReaderSession(context.session, context.doc);
  context.state.exporting = false;
  context.state.handlingSelection = false;
  clearHighlightThemeState(context.doc);

  if (context.state.highlightFocusTimeout !== null) {
    context.doc.defaultView?.clearTimeout(context.state.highlightFocusTimeout);
    context.state.highlightFocusTimeout = null;
  }

  context.doc.defaultView?.getSelection()?.removeAllRanges();
}

export function focusReaderHighlight(context: ReaderSessionOperationContext, id: string): void {
  const highlight = findReaderHighlight(context.state.highlights, id);
  if (!highlight) {
    return;
  }

  context.state.highlightFocusTimeout = context.highlightManager.focusHighlight(
    highlight,
    context.state.highlightFocusTimeout,
    context.doc.defaultView ?? window
  );
}

export function removeReaderHighlight(context: ReaderSessionOperationContext, id: string): void {
  if (context.state.exporting) {
    return;
  }

  const index = context.state.highlights.findIndex((highlight) => highlight.id === id);
  if (index === -1) {
    return;
  }

  const [removed] = context.state.highlights.splice(index, 1);
  context.highlightManager.unwrapHighlight(removed);
  syncReaderHighlightsUi(context);
  context.panelCoordinator.applyHint(
    context.state.highlights.length ? 'panel' : 'noHighlights',
    context.state.highlights.length
  );
}

export function submitReaderHighlightEdit(
  context: ReaderSessionOperationContext,
  id: string,
  nextComment: string
): void {
  if (context.state.exporting) {
    return;
  }

  const highlight = findReaderHighlight(context.state.highlights, id);
  if (!highlight) {
    context.panelCoordinator.stopEditing();
    return;
  }

  context.highlightManager.updateComment(highlight, nextComment);
  syncReaderHighlightsUi(context);
  context.panelCoordinator.applyHint('panel', context.state.highlights.length);
  context.panelCoordinator.stopEditing();
}

function syncReaderHighlightsUi(context: ReaderSessionOperationContext): void {
  context.highlightManager.sortByDocumentOrder(context.state.highlights);
  context.panelCoordinator.updateHighlights(context.state.highlights);
}

function createDetachedReaderHighlight(
  doc: Document,
  id: string,
  selectedHtml: string,
  selectedText: string,
  comment: string,
  fragmentUrl: string
): ReaderHighlightRecord {
  const wrapper = doc.createElement('mark');
  wrapper.className = 'aiob-reader-highlight';
  wrapper.dataset.readerHighlightId = id;
  const trimmedComment = comment.trim();
  if (trimmedComment) {
    wrapper.dataset.readerComment = trimmedComment;
  }
  wrapper.textContent = selectedText;

  return {
    id,
    selectedHtml,
    selectedText,
    comment: trimmedComment,
    fragmentUrl,
    wrapper,
    wrapperSegments: [wrapper],
    createdAt: Date.now()
  };
}

function findReaderHighlight(
  highlights: ReaderHighlightRecord[],
  id: string
): ReaderHighlightRecord | undefined {
  return highlights.find((highlight) => highlight.id === id);
}

