export function initClipFlow(options: InitClipFlowOptions): ClipFlowHandlers {
  const {
    document,
    window,
    messaging,
    runtimeState,
    selectionTracker,
    selectionController,
    extractorRegistry,
    showSupportProgress
  } = options;

  async function emitClipError(error: AppError): Promise<void> {
    const errorHandler = getErrorHandler();
    await errorHandler.handle(error, { suppressNotifications: true });

    try {
      await messaging.send({ type: 'CLIP_ERROR', error });
    } catch (sendError) {
      const message = sendError instanceof Error ? sendError.message : String(sendError);
      const contextInput: { url: string; type?: string } = { url: location.href };
      const errorType = error.context?.type as string | undefined;
      if (errorType !== undefined) {
        contextInput.type = errorType;
      }
      const dispatchError = extractionErrors.dispatchFailure(message, contextInput);
      const handler = getErrorHandler();
      await handler.handle(dispatchError, { suppressNotifications: true });
    }
  }

  async function handleClip(): Promise<void> {
    const url = location.href;
    const doc = document;
    const clipMode = runtimeState.getClipMode();
    if (clipMode !== 'selection') {
      showSupportProgress?.({
        value: 8,
        label: '正在准备网页剪藏'
      });
    }
    try {
      let result: { markdown?: string; type?: string } | undefined;

      if (clipMode === 'selection') {
        let selectionInfo = selectionTracker.resolveActiveSelection();
        if (
          (!selectionInfo ||
            selectionInfo.selection.rangeCount === 0 ||
            selectionInfo.selection.isCollapsed) &&
          runtimeState.getLastSelectionSnapshot()
        ) {
          selectionInfo = selectionTracker.restoreSelectionFromSnapshot(
            runtimeState.getLastSelectionSnapshot()
          );
        }

        const selection = selectionInfo?.selection ?? null;

        if (!selection || selection.rangeCount === 0 || selection.isCollapsed) {
          throw extractionErrors.noSelection({
            url,
            type: 'selection',
            selectionLength: selection ? selection.toString().length : 0
          });
        }

        if (isVideoSessionActive(doc)) {
          await selectionController.handleVideoSelectionClip(doc, url, selection);
          runtimeState.setClipMode('full');
          runtimeState.setLastSelectionSnapshot(null);
          return;
        }

        const clip = await selectionController.handleSelectionClip(doc, url, selection);
        runtimeState.setClipMode('full');
        runtimeState.setLastSelectionSnapshot(null);
        if (!clip) {
          return;
        }
        showSupportProgress?.({
          value: 16,
          label: '正在发送选区剪藏'
        });
        result = clip;
      } else {
        result = await extractorRegistry.extract({ url, document: doc });
      }

      if (!result || !result.markdown) {
        const noMarkdownContext: { url: string; type?: string } = { url };
        const resultType = result?.type;
        if (resultType !== undefined) {
          noMarkdownContext.type = resultType;
        }
        throw extractionErrors.noMarkdown(noMarkdownContext);
      }

      try {
        await messaging.send({ type: 'CLIP_RESULT', payload: result as MessagePayload });
      } catch (sendError) {
        const message = sendError instanceof Error ? sendError.message : String(sendError);
        const dispatchContext: { url: string; type?: string } = { url };
        const resultType = result?.type;
        if (resultType !== undefined) {
          dispatchContext.type = resultType;
        }
        throw extractionErrors.dispatchFailure(message, dispatchContext);
      }
    } catch (error) {
      const appError = normalizeToAppError(error, {
        code: 'CONTENT_CLIP_FAILURE',
        domain: 'content',
        defaultMessage: 'Clip failed due to an unexpected error.',
        context: { url, mode: clipMode }
      });
      await emitClipError(appError);
    }
  }

  const handleModifierKey = (event: KeyboardEvent): void => {
    syncModifierState(runtimeState.getModifierState(), event);
  };

  const handleWindowBlur = (): void => {
    runtimeState.resetSelectionTracking();
  };

  const handlePrimaryMouseDown = (event: MouseEvent): void => {
    if (event.button !== 0) {
      runtimeState.setSelectionModifierActive(false);
      return;
    }
    syncModifierState(runtimeState.getModifierState(), event);
    const fragmentClipperConfig = runtimeState.getFragmentClipperConfig();
    if (!fragmentClipperConfig.selectionModifierEnabled) {
      runtimeState.setSelectionModifierActive(false);
      return;
    }
    runtimeState.setSelectionModifierActive(
      shouldTriggerSelectionWithModifiers(fragmentClipperConfig, runtimeState.getModifierState())
    );
  };

  const handleAutoSelectionClip = (event: MouseEvent): void => {
    if (event.button !== 0) {
      return;
    }
    if (isReaderSessionActive(document)) {
      return;
    }
    syncModifierState(runtimeState.getModifierState(), event);
    const fragmentClipperConfig = runtimeState.getFragmentClipperConfig();
    const modifierRequired = fragmentClipperConfig.selectionModifierEnabled;
    const modifiersSatisfied =
      runtimeState.isSelectionModifierActive() ||
      shouldTriggerSelectionWithModifiers(fragmentClipperConfig, runtimeState.getModifierState());
    if (modifierRequired && !modifiersSatisfied) {
      runtimeState.setSelectionModifierActive(false);
      return;
    }

    const selectionInfo = selectionTracker.resolveActiveSelection();
    if (!selectionInfo) {
      runtimeState.setSelectionModifierActive(false);
      return;
    }

    const selection = selectionInfo.selection;
    if (!selection || selection.rangeCount === 0 || selection.isCollapsed) {
      runtimeState.setSelectionModifierActive(false);
      return;
    }
    if (!selection.toString().trim()) {
      runtimeState.setSelectionModifierActive(false);
      return;
    }
    if (
      selectionTracker.isSelectionInsideUi(selection) ||
      selectionTracker.isSelectionEditable(selection)
    ) {
      runtimeState.setSelectionModifierActive(false);
      return;
    }
    if (runtimeState.getAutoSelectionInFlight()) {
      return;
    }

    runtimeState.setAutoSelectionInFlight(true);
    runtimeState.setClipMode('selection');
    void handleClip().finally(() => {
      runtimeState.setAutoSelectionInFlight(false);
      runtimeState.setSelectionModifierActive(false);
    });
  };

  const handleSelectionChange = (): void => {
    selectionTracker.handleSelectionChange();
  };

  const handleSelectStart = (_event: Event): void => {
    selectionTracker.handleSelectStart();
  };

  return {
    handleClip,
    handleAutoSelectionClip,
    handleModifierKey,
    handleWindowBlur,
    handlePrimaryMouseDown,
    handleSelectionChange,
    handleSelectStart
  };
}

type ContentSessionRegistryState = {
  readerSession: unknown | null;
  videoSession: unknown | null;
};

const states = new WeakMap<Document, ContentSessionRegistryState>();

function getState(doc: Document = document): ContentSessionRegistryState {
  let state = states.get(doc);
  if (!state) {
    state = {
      readerSession: null,
      videoSession: null
    };
    states.set(doc, state);
  }
  return state;
}

function getRoot(doc: Document = document): HTMLElement {
  return doc.documentElement;
}

function setDatasetFlag(root: HTMLElement, key: string, active: boolean): void {
  if (active) {
    root.dataset[key] = 'true';
    return;
  }
  delete root.dataset[key];
}

export function markContentRuntimeInitialized(doc: Document = document): boolean {
  const root = getRoot(doc);
  if (root.dataset.aiobContentRuntime === 'true') {
    return false;
  }
  root.dataset.aiobContentRuntime = 'true';
  return true;
}

export function registerReaderSession(session: unknown, doc: Document = document): void {
  const state = getState(doc);
  state.readerSession = session;
  setDatasetFlag(getRoot(doc), 'aiobReaderActive', true);
}

export function clearReaderSession(session?: unknown, doc: Document = document): void {
  const state = getState(doc);
  if (session !== undefined && state.readerSession !== session) {
    return;
  }
  state.readerSession = null;
  setDatasetFlag(getRoot(doc), 'aiobReaderActive', false);
}

export function getReaderSession<T>(doc: Document = document): T | null {
  const state = getState(doc);
  return (state.readerSession as T | null) ?? null;
}

export function isReaderSessionActive(doc: Document = document): boolean {
  const state = getState(doc);
  return state.readerSession !== null || getRoot(doc).dataset.aiobReaderActive === 'true';
}

export function registerVideoSession(session: unknown, doc: Document = document): void {
  const state = getState(doc);
  state.videoSession = session;
  setDatasetFlag(getRoot(doc), 'aiobVideoActive', true);
}

export function clearVideoSession(session?: unknown, doc: Document = document): void {
  const state = getState(doc);
  if (session !== undefined && state.videoSession !== session) {
    return;
  }
  state.videoSession = null;
  setDatasetFlag(getRoot(doc), 'aiobVideoActive', false);
}

export function getVideoSession<T>(doc: Document = document): T | null {
  const state = getState(doc);
  return (state.videoSession as T | null) ?? null;
}

export function isVideoSessionActive(doc: Document = document): boolean {
  const state = getState(doc);
  return state.videoSession !== null || getRoot(doc).dataset.aiobVideoActive === 'true';
}

export function __resetContentSessionRegistryForTests(doc: Document = document): void {
  const state = getState(doc);
  state.readerSession = null;
  state.videoSession = null;
  const root = getRoot(doc);
  delete root.dataset.aiobContentRuntime;
  delete root.dataset.aiobReaderActive;
  delete root.dataset.aiobVideoActive;
}

import type { VideoPanelCallbacks, VideoPanelTexts } from './application/videoPanelModel';
import type { VideoSessionViewFactory } from './application/videoSessionView';
import { VideoPanelPresenter } from './videoPanelPresenter';
import type { VideoHintState } from './videoHintManager';
import { VideoHintManager } from './videoHintManager';
import {
  buildVideoHintContext,
  partitionVideoPanelCaptures,
  type VideoSessionState
} from './sessionState';
import type { VideoFragmentCapture } from './types';
import type { ExportDestinationSurfacePreview } from '@options/stitch/types';

export interface VideoSessionDomListenerHandlers {
  onMouseDown(event: MouseEvent): void;
  onKeyDown(event: KeyboardEvent): void;
  onKeyUp(event: KeyboardEvent): void;
  onWindowBlur(): void;
}

export class VideoSessionDomController {
  private panelPresenter: VideoPanelPresenter | null = null;
  private panel = null as ReturnType<VideoSessionViewFactory['createView']> | null;
  private listeners: VideoSessionDomListenerHandlers | null = null;

  constructor(
    private readonly doc: Document,
    private readonly viewFactory: VideoSessionViewFactory,
    private readonly hintManager: VideoHintManager
  ) {}

  async waitForDocumentReady(): Promise<void> {
    if (this.doc.body) {
      return;
    }

    if (this.doc.readyState === 'loading') {
      await new Promise<void>((resolve) => {
        this.doc.addEventListener('DOMContentLoaded', () => resolve(), { once: true });
      });
      if (this.doc.body) {
        return;
      }
    }

    if (typeof MutationObserver === 'undefined') {
      if (this.doc.body) {
        return;
      }
      await new Promise<void>((resolve) => {
        const view = this.doc.defaultView ?? window;
        const interval = view.setInterval(() => {
          if (this.doc.body) {
            view.clearInterval(interval);
            resolve();
          }
        }, 16);
      });
      return;
    }

    await new Promise<void>((resolve) => {
      const target = this.doc.documentElement ?? this.doc;
      const observer = new MutationObserver(() => {
        if (this.doc.body) {
          observer.disconnect();
          resolve();
        }
      });
      try {
        observer.observe(target, { childList: true, subtree: target === this.doc.documentElement });
      } catch {
        resolve();
        return;
      }
      if (this.doc.body) {
        observer.disconnect();
        resolve();
      }
    });
  }

  mountPanel(
    callbacks: VideoPanelCallbacks,
    texts: VideoPanelTexts,
    options: { initialCollapsed?: boolean } = {}
  ): void {
    this.panel = this.viewFactory.createView(callbacks, texts, options);
    if (options.initialCollapsed) {
      this.panel.collapse?.();
    }
    this.panelPresenter = new VideoPanelPresenter(this.panel);
    this.panelPresenter.updateTexts(texts);
    this.panelPresenter.render({ timestamps: [], fragments: [] });
  }

  updateTexts(texts: VideoPanelTexts): void {
    this.panelPresenter?.updateTexts(texts);
  }

  updateDestination(destination: ExportDestinationSurfacePreview | undefined): void {
    this.panel?.updateDestination?.(destination);
  }

  syncPanel(
    state: VideoSessionState,
    getFragmentElement: (capture: VideoFragmentCapture) => HTMLElement | null
  ): number {
    if (!this.panelPresenter) {
      return 0;
    }

    const groups = partitionVideoPanelCaptures(state.captures, getFragmentElement);
    return this.panelPresenter.render(groups);
  }

  applyHint(
    state: VideoHintState,
    sessionState: Pick<VideoSessionState, 'videoElement' | 'captures'>
  ): void {
    const { hint } = this.hintManager.apply(state, buildVideoHintContext(sessionState));
    this.panel?.updateHint(hint);
  }

  refreshHint(sessionState: Pick<VideoSessionState, 'videoElement' | 'captures'>): void {
    const { hint } = this.hintManager.refresh(buildVideoHintContext(sessionState));
    this.panel?.updateHint(hint);
  }

  beginEditingCapture(captureId: string, comment: string): void {
    this.panel?.beginEditingCapture(captureId, comment);
  }

  stopEditing(): void {
    this.panel?.stopEditing();
  }

  collapsePanel(): void {
    this.panel?.collapse?.();
  }

  registerInteractionHandlers(handlers: VideoSessionDomListenerHandlers): void {
    this.listeners = handlers;
    this.doc.addEventListener('mousedown', handlers.onMouseDown, true);
    this.doc.addEventListener('keydown', handlers.onKeyDown, true);
    this.doc.addEventListener('keyup', handlers.onKeyUp, true);
    this.doc.defaultView?.addEventListener('blur', handlers.onWindowBlur, true);
  }

  removeInteractionHandlers(): void {
    if (!this.listeners) {
      return;
    }
    this.doc.removeEventListener('mousedown', this.listeners.onMouseDown, true);
    this.doc.removeEventListener('keydown', this.listeners.onKeyDown, true);
    this.doc.removeEventListener('keyup', this.listeners.onKeyUp, true);
    this.doc.defaultView?.removeEventListener('blur', this.listeners.onWindowBlur, true);
    this.listeners = null;
  }

  destroy(): void {
    this.removeInteractionHandlers();
    this.panel?.destroy();
    this.panel = null;
    this.panelPresenter = null;
  }
}

