import {
  buildAppShell,
  buildPanelStack,
  buildScrollSection,
  buildSidebar
} from '@options/stitch/render/shellBuilders';
import { renderPreviewView } from '@options/stitch/render/renderStitchView';
import { clear, el } from '@options/stitch/ui/dom';
import { previewUi } from '@options/stitch/ui/components';
import { getFooterMeta, getFooterView, getSettingsView } from '@options/stitch/schema/registry';
import type {
  PreviewContent,
  PreviewStoreState,
  SchemaContext,
  ViewSchema
} from '@options/stitch/types';
import type { Language } from '@i18n';
import { RUNTIME_SURFACE_RESOURCE_IDS } from './productionStitchStateMapper';
import { setScrollTopImmediately } from './productionStitchScrollGuard';
import { createProductionStitchRenderControls } from './productionStitchRenderControls';

interface ProductionStitchRenderWidgetHost {
  createWidgetFactory(widgetType: string): unknown;
  destroyWidgets(): void;
  flushDirtyWidgets(): void;
  mountWidget(widgetType: string, host: HTMLElement): void;
}

interface ProductionStitchSchemaRenderer {
  renderView(view: never): HTMLElement;
}

interface ProductionStitchRenderLifecycleOptions {
  mountRoot: HTMLElement;
  getAppData(): PreviewContent;
  getCurrentLanguage(): Language;
  getState(): PreviewStoreState;
  setState(state: PreviewStoreState): void;
  createSchemaContext(): SchemaContext;
  dispatch(actionId: string, args?: unknown[], value?: unknown, event?: Event): void;
  schemaRenderer: ProductionStitchSchemaRenderer;
  widgetHost: ProductionStitchRenderWidgetHost;
}

export interface ProductionStitchRenderLifecycle {
  applySystemThemePreferenceChange(): void;
  openResource(resourceId: string): void;
  render(): void;
  renderActiveResourceModal(): void;
  scrollToPanel(panelId: string): void;
  syncHighlightThemeControls(): void;
  syncModifierControls(): void;
  syncPreviewThemeControls(): void;
}

export function createProductionStitchRenderLifecycle(
  options: ProductionStitchRenderLifecycleOptions
): ProductionStitchRenderLifecycle {
  const { mountRoot } = options;
  const controls = createProductionStitchRenderControls({
    mountRoot,
    getState: () => options.getState()
  });

  function getState(): PreviewStoreState {
    return options.getState();
  }

  function createRenderContext() {
    return {
      ...options.createSchemaContext(),
      el,
      ui: previewUi,
      dispatch: options.dispatch,
      mountWidget: (widgetType: string, host: HTMLElement) =>
        options.widgetHost.mountWidget(widgetType, host)
    };
  }

  function renderSidebar(): HTMLElement {
    const context = options.createSchemaContext();
    const state = getState();
    return buildSidebar({
      el,
      brand: context.appData.brand,
      settingsTitle: '',
      resourcesTitle: '',
      runtimeTitle: options.getCurrentLanguage() === 'en' ? 'Runtime UI' : '运行时界面',
      navItems: context.appData.nav,
      sidebarLinks: context.appData.sidebarLinks,
      surfaceLinks: context.appData.surfaceLinks,
      activePanel: state.activePanel,
      activeResource: state.activeResource,
      onPanelClick: scrollToPanel,
      onFooterClick: openResource
    });
  }

  function renderSectionStack(): HTMLElement {
    return buildPanelStack({
      el,
      items: options.getAppData().nav,
      renderSection: (panelId) => {
        const view = getSettingsView(panelId, options.createSchemaContext());
        const content = view ? options.schemaRenderer.renderView(view as never) : el('div');
        return buildScrollSection({ el, panelId, content });
      }
    });
  }

  function render(): void {
    const previousMain = mountRoot.querySelector('.main');
    const previousScrollTop = previousMain instanceof HTMLElement ? previousMain.scrollTop : 0;
    const previousWindowScroll = {
      x: window.scrollX,
      y: window.scrollY
    };
    options.widgetHost.flushDirtyWidgets();
    options.widgetHost.destroyWidgets();
    clear(mountRoot).append(
      buildAppShell({
        el,
        sidebar: renderSidebar(),
        panelStack: renderSectionStack()
      })
    );
    const nextMain = mountRoot.querySelector('.main');
    const restoreScroll = () => {
      const currentMain = mountRoot.querySelector('.main');
      if (currentMain instanceof HTMLElement) {
        setScrollTopImmediately(currentMain, previousScrollTop);
      }
      if (window.scrollX !== previousWindowScroll.x || window.scrollY !== previousWindowScroll.y) {
        window.scrollTo(previousWindowScroll.x, previousWindowScroll.y);
      }
    };
    if (nextMain instanceof HTMLElement) {
      restoreScroll();
      bindScrollSync(nextMain);
      queueMicrotask(restoreScroll);
      window.requestAnimationFrame?.(() => restoreScroll());
    }
    const chartHost = mountRoot.querySelector<HTMLElement>('[data-role="usage-chart-shell"]');
    if (chartHost) {
      previewUi.renderUsageChart(chartHost, options.getAppData().overview.history);
    }
    controls.syncPreviewThemeControls();
    controls.syncHighlightThemeControls();
    controls.syncModifierControls();
    renderActiveResourceModal();
  }

  function openResource(resourceId: string): void {
    if (RUNTIME_SURFACE_RESOURCE_IDS.has(resourceId)) {
      return;
    }
    const meta = getFooterMeta(resourceId);
    if (!meta) {
      return;
    }
    if (meta.openMode === 'page') {
      const href = resourceId === 'onboarding' ? '../onboarding/index.html' : meta.href;
      window.open(href ?? `./${resourceId}.html`, '_blank', 'noopener,noreferrer');
      return;
    }
    options.setState({
      ...getState(),
      activeResource: resourceId
    });
    renderActiveResourceModal();
  }

  function renderActiveResourceModal(): void {
    mountRoot.querySelectorAll('.resource-modal-overlay').forEach((modal) => modal.remove());
    const state = getState();
    if (!state.activeResource) {
      return;
    }
    const view = getFooterView(state.activeResource, options.createSchemaContext());
    const modal = view ? renderPreviewView(view, createRenderContext()) : null;
    if (modal) {
      mountRoot.querySelector<HTMLElement>('[data-modal-host="true"]')?.append(modal);
    }
  }

  function scrollToPanel(panelId: string): void {
    options.setState({
      ...getState(),
      activePanel: panelId
    });
    const main = mountRoot.querySelector<HTMLElement>('.main');
    const section = mountRoot.querySelector<HTMLElement>(`[data-panel-id="${panelId}"]`);
    if (main && section) {
      const top = Math.max(section.offsetTop - 12, 0);
      if (typeof main.scrollTo === 'function') {
        main.scrollTo({ top, behavior: 'smooth' });
      } else {
        main.scrollTop = top;
      }
    }
    syncActiveLinks();
  }

  function bindScrollSync(main: HTMLElement): void {
    main.addEventListener(
      'scroll',
      () => {
        const sections = Array.from(
          mountRoot.querySelectorAll<HTMLElement>('[data-scroll-section="true"]')
        );
        const threshold = main.scrollTop + 120;
        let nextActive = sections[0]?.dataset.panelId ?? getState().activePanel;
        sections.forEach((section) => {
          if (section.offsetTop <= threshold) {
            nextActive = section.dataset.panelId ?? nextActive;
          }
        });
        if (nextActive !== getState().activePanel) {
          options.setState({
            ...getState(),
            activePanel: nextActive
          });
          syncActiveLinks();
        }
      },
      { passive: true }
    );
  }

  function syncActiveLinks(): void {
    const state = getState();
    mountRoot.querySelectorAll<HTMLElement>('[data-nav-panel]').forEach((button) => {
      button.classList.toggle('is-active', button.dataset.navPanel === state.activePanel);
    });
    mountRoot.querySelectorAll<HTMLElement>('[data-footer-panel]').forEach((button) => {
      button.classList.toggle('is-active', button.dataset.footerPanel === state.activeResource);
    });
  }

  return {
    applySystemThemePreferenceChange: controls.applySystemThemePreferenceChange,
    openResource,
    render,
    renderActiveResourceModal,
    scrollToPanel,
    syncHighlightThemeControls: controls.syncHighlightThemeControls,
    syncModifierControls: controls.syncModifierControls,
    syncPreviewThemeControls: controls.syncPreviewThemeControls
  };
}

import { mergeOptions } from '@shared/config/optionsMerger';
import { YamlConfigWidget } from '@options/widgets/YamlConfigWidget';
import type { Messages } from '@i18n';
import type { CompleteOptions } from '@shared/types/options';
import type { PreviewContent, PreviewStoreState } from '@options/stitch/types';
import type { WidgetFactory } from '@options/schema-runtime/contracts';
import type { WidgetMountContract as OptionsWidgetMountContract } from '@options/widgets/contracts';

interface ProductionStitchWidgetHostOptions {
  getDraft(): CompleteOptions;
  getState(): PreviewStoreState;
  getMessages(): Messages | null;
  ensureVaultRouter(): void;
  mergePartialIntoDraft(partial: Partial<CompleteOptions>): void;
  syncDefaultVaultFromRest(): void;
  refreshAppData(): void;
  scheduleDraftSave(): void;
}

export interface ProductionStitchWidgetHost {
  collectDraftWithWidgets(): CompleteOptions;
  createWidgetFactory(widgetType: string): WidgetFactory<PreviewStoreState, PreviewContent> | null;
  destroyWidgets(): void;
  flushDirtyWidgets(): void;
  markDirty(key: string): void;
  mountWidget(widgetType: string, host: HTMLElement): void;
  resetDirty(): void;
}

function createWidget(
  widgetType: string
): OptionsWidgetMountContract<Record<string, unknown>, Partial<CompleteOptions>> | null {
  return widgetType === 'yaml-config'
    ? (new YamlConfigWidget() as OptionsWidgetMountContract<
        Record<string, unknown>,
        Partial<CompleteOptions>
      >)
    : null;
}

function applyDisabledExperimentalState(
  collected: CompleteOptions,
  state: PreviewStoreState
): CompleteOptions {
  collected.pageSummary.enabled = false;
  collected.readingOverlaySummary.enabled = false;
  collected.subtitleTranslation.enabled = false;
  collected.interfaceTheme = state.interfaceThemePreference ?? state.previewTheme;
  return collected;
}

export function createProductionStitchWidgetHost(
  options: ProductionStitchWidgetHostOptions
): ProductionStitchWidgetHost {
  const widgetInstances = new Set<
    OptionsWidgetMountContract<Record<string, unknown>, Partial<CompleteOptions>>
  >();
  const dirtyWidgetKeys = new Set<string>();

  function collectBaseDraft(): CompleteOptions {
    const draft = options.getDraft();
    const collected = {
      ...mergeOptions(draft),
      ...draft
    } as CompleteOptions;
    return applyDisabledExperimentalState(collected, options.getState());
  }

  function collectDraftWithWidgets(): CompleteOptions {
    if (!options.getDraft().vaultRouter?.vaults?.length) {
      options.ensureVaultRouter();
    }
    if (!dirtyWidgetKeys.size) {
      return collectBaseDraft();
    }
    widgetInstances.forEach((widget) => {
      const partial = widget.collect?.();
      if (partial) {
        options.mergePartialIntoDraft(partial);
      }
    });
    options.syncDefaultVaultFromRest();
    dirtyWidgetKeys.clear();
    options.refreshAppData();
    return collectBaseDraft();
  }

  function flushDirtyWidgets(): void {
    if (dirtyWidgetKeys.size) {
      collectDraftWithWidgets();
    }
  }

  function destroyWidgets(): void {
    widgetInstances.forEach((widget) => {
      widget.destroy();
    });
    widgetInstances.clear();
  }

  function mountWidget(widgetType: string, host: HTMLElement): void {
    const widget = createWidget(widgetType);
    if (!widget) {
      host.textContent = `[Missing widget] ${widgetType}`;
      return;
    }
    widgetInstances.add(widget);
    widget.mount(
      host,
      { options: options.getDraft(), messages: options.getMessages() },
      {
        notifyDirty: (keys = [], meta) => {
          keys.forEach((key) => dirtyWidgetKeys.add(key));
          if (meta?.invalid) {
            options.refreshAppData();
            return;
          }
          options.scheduleDraftSave();
        },
        reportError: (scope, error) => {
          console.error(`[ProductionStitchShell:${scope}]`, error);
        }
      }
    );
  }

  return {
    collectDraftWithWidgets,
    createWidgetFactory(widgetType) {
      if (widgetType !== 'yaml-config') {
        return null;
      }
      return () => createWidget(widgetType) as never;
    },
    destroyWidgets,
    flushDirtyWidgets,
    markDirty(key) {
      dirtyWidgetKeys.add(key);
    },
    mountWidget,
    resetDirty() {
      dirtyWidgetKeys.clear();
    }
  };
}

import { BaseComponent } from '../../../ui/foundation/lifecycle/BaseComponent';
import { Sidebar, type SidebarConfig, type SidebarFooterLink } from './Sidebar';
import { MainContent } from './MainContent';
import type { NavigationItem } from './Navigation';
import type { OptionsStateManager } from '../../state/StateManager';
import { NavigationController } from './NavigationController';
import { ModalController, type ModalBindingConfig } from '../infrastructure/ModalController';
import type { FormSectionRegistry } from '../formSections/formSectionManager';

export interface OptionsAppConfig {
  stateManager: OptionsStateManager;
  initialSection?: string;
  navigationItems?: NavigationItem[];
  brand?: SidebarConfig['brand'];
  footerLinks?: SidebarConfig['footerLinks'];
  modalBindings?: ModalBindingConfig[];
  formRegistry: FormSectionRegistry;
}

export interface OptionsAppUIConfig {
  modalBindings?: ModalBindingConfig[];
}

/**
 * Root composition component that wires the sidebar and primary content area together.
 */
export class OptionsApp extends BaseComponent<OptionsAppConfig> {
  private stateManager: OptionsStateManager | null = null;
  private sidebar: Sidebar | null = null;
  private content: MainContent | null = null;
  private navigationController: NavigationController | null = null;
  private modalController: ModalController | null = null;
  private formRegistry: FormSectionRegistry | null = null;

  render(config: OptionsAppConfig): HTMLElement {
    this.assertActive();
    this.stateManager = config.stateManager;
    this.formRegistry = config.formRegistry;

    const shell = this.createElement(
      'div',
      'aobx-shell grid grid-cols-1 lg:grid-cols-[252px_minmax(0,1fr)] h-screen min-h-screen overflow-hidden'
    );

    const sidebarHost = this.createElement('div');
    this.sidebar = new Sidebar(sidebarHost);
    if (this.messages) {
      this.sidebar.setMessages(this.messages);
    }
    const sidebarElement = this.sidebar.render(this.buildSidebarConfig(config));
    const sidebarNode = (sidebarElement ??
      sidebarHost.firstElementChild ??
      sidebarHost) as HTMLElement;
    sidebarNode.classList.add(
      'aobx-shell__sidebar',
      'border-b',
      'lg:border-b-0',
      'lg:border-r',
      'border-base-300',
      'bg-base-100',
      'p-6',
      'pb-4',
      'flex',
      'flex-col',
      'gap-5',
      'lg:sticky',
      'lg:top-0',
      'lg:h-screen',
      'lg:max-h-screen',
      'lg:self-start',
      'lg:overflow-y-auto'
    );

    if (!this.stateManager) {
      throw new Error('[OptionsApp] State manager missing during render.');
    }
    const contentHost = this.createElement('div');
    this.content = new MainContent(contentHost);
    if (this.messages) {
      this.content.setMessages(this.messages);
    }
    const contentElement = this.content.render({
      stateManager: this.stateManager,
      ...(config.initialSection !== undefined && { initialSection: config.initialSection }),
      formRegistry: this.formRegistry
    });
    const contentNode = (contentElement ??
      contentHost.firstElementChild ??
      contentHost) as HTMLElement;
    contentNode.classList.add(
      'aobx-shell__content',
      'min-h-screen',
      'h-auto',
      'lg:h-screen',
      'lg:overflow-y-auto',
      'bg-base-200',
      'p-6',
      'px-[clamp(24px,4vw,48px)]'
    );

    shell.append(sidebarNode, contentNode);
    this.container.classList.add(
      'aobx-options-app',
      'min-h-screen',
      'bg-surface',
      'text-text',
      'font-ui',
      'text-md',
      'leading-[1.56]'
    );
    this.container.replaceChildren(shell);

    this.attachNavigationController(shell);
    if (config.modalBindings) {
      this.configureUI({ modalBindings: config.modalBindings });
    }

    return shell;
  }

  destroy(): void {
    this.navigationController?.dispose();
    this.navigationController = null;
    this.modalController?.dispose();
    this.modalController = null;
    this.sidebar?.destroy();
    this.content?.destroy();
    this.sidebar = null;
    this.content = null;
    this.stateManager = null;
    this.formRegistry = null;
    super.destroy();
  }

  async mountSection(sectionId: string, markActive: boolean = false): Promise<void> {
    await this.content?.mountSection(sectionId, markActive);
  }

  async preloadSections(sectionIds: string[]): Promise<void> {
    await this.content?.preloadSections(sectionIds);
  }

  unmountSection(sectionId: string): void {
    this.content?.unmountSection(sectionId);
  }

  async navigateTo(sectionId: string): Promise<void> {
    await this.content?.navigateTo(sectionId);
    this.sidebar?.setActiveNavigation(sectionId);
  }

  getMountedSection(sectionId: string): ReturnType<MainContent['getSectionInstance']> {
    return this.content?.getSectionInstance(sectionId) ?? null;
  }

  forEachSection(callback: Parameters<MainContent['forEachSection']>[0]): void {
    this.content?.forEachSection(callback);
  }

  configureUI(config: OptionsAppUIConfig = {}): void {
    this.assertActive();
    const doc = this.container.ownerDocument ?? (typeof document !== 'undefined' ? document : null);
    const win = doc?.defaultView ?? (typeof window !== 'undefined' ? window : null);

    this.modalController?.dispose();
    this.modalController = null;

    if (doc) {
      this.modalController = new ModalController({
        document: doc,
        window: win,
        ...(config.modalBindings !== undefined && { bindings: config.modalBindings })
      });
    }
  }

  private buildSidebarConfig(config: OptionsAppConfig): SidebarConfig {
    const navigation: SidebarConfig['navigation'] = {
      activeId: config.initialSection ?? 'usage',
      onNavigate: (id: string) => {
        void this.navigateTo(id);
      }
    };

    if (config.navigationItems && config.navigationItems.length > 0) {
      navigation.items = config.navigationItems;
    }

    const brand = config.brand ?? this.buildDefaultBrand();
    return {
      footerLinks: config.footerLinks ?? this.buildDefaultFooterLinks(),
      navigation,
      ...(brand !== undefined && { brand })
    };
  }

  private buildDefaultBrand(): SidebarConfig['brand'] | undefined {
    if (!this.messages) {
      return undefined;
    }

    return {
      title: this.messages.extensionName ?? 'All in Obsidian',
      ...(this.messages.extensionSubtitle !== undefined && {
        subtitle: this.messages.extensionSubtitle
      }),
      ...(this.messages.versionNumber !== undefined && { version: this.messages.versionNumber }),
      logoUrl: '../icons/bannerlogo-128.png'
    };
  }

  private buildDefaultFooterLinks(): SidebarFooterLink[] {
    const links: SidebarFooterLink[] = [];
    if (this.messages?.onboardingLinkText) {
      links.push({
        label: this.messages.onboardingLinkText,
        href: '../onboarding/index.html',
        external: true
      });
    }

    links.push({
      label: this.messages?.footerSupportLink ?? 'Support',
      id: 'supportLink'
    });

    links.push({
      label: this.messages?.footerSuggestionsLink ?? 'Suggestions',
      id: 'suggestionsLink'
    });

    links.push({
      label: this.messages?.footerContactLink ?? 'Contact',
      id: 'contactLink'
    });

    return links;
  }

  private attachNavigationController(root: HTMLElement): void {
    this.navigationController?.dispose();
    const doc = root.ownerDocument ?? (typeof document !== 'undefined' ? document : null);
    const win = doc?.defaultView ?? (typeof window !== 'undefined' ? window : null);
    this.navigationController = new NavigationController({
      root,
      document: doc,
      window: win
    });
  }
}

import { getAvailableLanguages, type Language } from '@i18n';
import type { IOptionsRepository } from '@shared/repositories';
import { UiSelect as DaisySelect } from '@ui/primitives/select';
import type { SectionRenderContext } from './BaseSection';
import { BaseSection } from './BaseSection';
import { changeLanguage } from '../../app/optionsActions';
import { runLanguagePreferenceAction } from '../../app/actions';

interface LanguagePreferenceSnapshot {
  languagePreference?: {
    code?: Language;
  };
}

export class LanguageSection extends BaseSection<SectionRenderContext> {
  private readonly optionsRepo: IOptionsRepository;
  private unsubscribeState: (() => void) | null = null;
  private unsubscribeRepo: (() => void) | null = null;
  private select: HTMLSelectElement | null = null;
  private isProcessing = false;
  private pendingPersistLanguage: Language | null = null;
  private currentLanguage: Language = 'en';

  constructor(container: HTMLElement, optionsRepo: IOptionsRepository) {
    super(container);
    this.optionsRepo = optionsRepo;
  }

  protected renderWithState(context: SectionRenderContext): HTMLElement {
    this.applySectionChrome();
    const header = this.buildHeader();
    const body = this.buildBody();
    this.container.replaceChildren(header, body);

    const state = context.stateManager.getState();
    this.syncFromState(state.language);

    this.unsubscribeState?.();
    this.unsubscribeState = context.stateManager.subscribe((nextState) => {
      this.syncFromState(nextState.language);
    });

    this.subscribeToRepository();

    return this.container;
  }

  override destroy(): void {
    this.unsubscribeState?.();
    this.unsubscribeState = null;
    this.unsubscribeRepo?.();
    this.unsubscribeRepo = null;
    if (this.select) {
      this.select.removeEventListener('change', this.handleLanguageChange);
    }
    this.select = null;
    super.destroy();
  }

  private buildHeader(): HTMLElement {
    const meta = this.createElement('div', 'text-base-content/60 text-md');
    const selectHost = this.createElement('div');
    const select = new DaisySelect(selectHost).render({
      id: 'languageSelect',
      ariaLabel: this.messages?.languageLabel ?? 'Interface language',
      options: this.getLanguageOptions()
    });
    select.addEventListener('change', this.handleLanguageChange);

    meta.append(selectHost);
    this.select = select;
    return this.buildSectionHeader({
      title: this.messages?.languageSettings ?? 'Language Settings',
      actions: [meta],
      titleClassName: 'm-0 text-2xl font-semibold tracking-tight',
      titleWrapperClassName: 'flex items-center justify-between gap-3 text-base-content flex-wrap'
    });
  }

  private buildBody(): HTMLElement {
    const wrapper = this.createSectionBody();
    const hint = this.createElement(
      'p',
      'text-sm text-base-content/60 bg-base-200 border border-base-300 rounded-md p-3 my-3'
    );
    hint.textContent =
      this.messages?.languageSettings ??
      '修改下拉框后会重新加载界面文字；若翻译未实时更新，请稍候或再次尝试。';
    wrapper.append(hint);
    return wrapper;
  }

  private getLanguageOptions() {
    return getAvailableLanguages().map((language) => ({
      value: language.code,
      label: language.name,
      ...(language.dir === 'rtl' ? { dir: 'rtl' as const } : {}),
      dataAttributes: {
        ...(language.nativeName ? { nativeName: language.nativeName } : {}),
        ...(language.englishName ? { englishName: language.englishName } : {}),
        ...(language.region ? { region: language.region } : {}),
        ...(typeof language.textExpansion === 'number'
          ? { textExpansion: String(language.textExpansion) }
          : {})
      }
    }));
  }

  private syncFromState(language: string): void {
    this.currentLanguage = language as Language;
    if (this.select) {
      this.select.value = language;
    }
  }

  private handleLanguageChange = (event: Event): void => {
    if (this.isProcessing || !this.select) {
      return;
    }

    const nextLanguage = (event.target as HTMLSelectElement).value as Language;
    void this.applyLanguage(nextLanguage, { persist: true });
  };

  private async applyLanguage(language: Language, options: { persist: boolean }): Promise<void> {
    if (this.isProcessing) {
      return;
    }
    this.isProcessing = true;
    if (this.select) {
      this.select.disabled = true;
    }

    try {
      if (options.persist) {
        this.pendingPersistLanguage = language;
      }
      await runLanguagePreferenceAction(
        language,
        {
          changeLanguage,
          optionsRepository: this.optionsRepo
        },
        { persist: options.persist }
      );
      this.currentLanguage = language;
      this.syncFromState(language);
    } catch (error) {
      if (options.persist) {
        this.pendingPersistLanguage = null;
      }
      console.error('[LanguageSection] Failed to change language:', error);
    } finally {
      if (this.select) {
        this.select.disabled = false;
      }
      this.isProcessing = false;
    }
  }

  private subscribeToRepository(): void {
    this.unsubscribeRepo?.();
    this.unsubscribeRepo = this.optionsRepo.onChange((options) => {
      const snapshot = this.extractLanguagePreference(
        options as Partial<LanguagePreferenceSnapshot>
      );
      if (!snapshot) {
        return;
      }
      if (this.pendingPersistLanguage && snapshot === this.pendingPersistLanguage) {
        this.pendingPersistLanguage = null;
        return;
      }
      if (snapshot === this.currentLanguage) {
        return;
      }
      void this.applyLanguage(snapshot, { persist: false });
    });
  }

  private extractLanguagePreference(options: Partial<LanguagePreferenceSnapshot>): Language | null {
    const pref = options.languagePreference?.code;
    return pref ?? null;
  }
}

import type { IOptionsRepository } from '@shared/repositories';
import type { PrivacyConsentSnapshot } from '@ui/domains/privacy';
import { PrivacySettings } from '@ui/domains/privacy';
import { BaseSection, type SectionRenderContext } from './BaseSection';
import { persistPrivacyConsentAction } from '../../app/actions';

export class PrivacySection extends BaseSection<SectionRenderContext> {
  private readonly optionsRepo: IOptionsRepository;
  private host: HTMLElement | null = null;
  private instance: PrivacySettings | null = null;
  private unsubscribeFromRepo: (() => void) | null = null;
  private cachedConsent: PrivacyConsentSnapshot | null = null;

  constructor(container: HTMLElement, optionsRepo: IOptionsRepository) {
    super(container);
    this.optionsRepo = optionsRepo;
  }

  protected renderWithState(): HTMLElement {
    this.applySectionChrome();

    const header = this.buildHeader();
    const body = this.buildBody();

    this.container.replaceChildren(header, body);
    this.renderPrivacySettings();
    this.subscribeToRepository();
    return this.container;
  }

  async refreshSettings(): Promise<void> {
    this.renderPrivacySettings();
  }

  async saveSettings(options?: { showInlineStatus?: boolean }): Promise<void> {
    if (!this.instance && this.host) {
      this.renderPrivacySettings();
    }
    if (this.instance) {
      await this.instance.saveSettings(options);
    }
  }

  destroy(): void {
    this.instance = null;
    this.host = null;
    this.unsubscribeFromRepo?.();
    this.unsubscribeFromRepo = null;
    super.destroy();
  }

  private buildHeader(): HTMLElement {
    return this.buildSectionHeader({
      title: this.messages?.privacySettingsTitle ?? '隐私与数据',
      description: this.messages?.privacySettingsDescription ?? '控制数据收集和错误报告'
    });
  }

  private buildBody(): HTMLElement {
    const container = this.createSectionBody();
    container.id = 'privacySettingsContainer';
    this.host = container;
    return container;
  }

  private renderPrivacySettings(): void {
    if (!this.host) {
      return;
    }

    try {
      // ✅ Stage 3 Week 2: PrivacySettings renders DaisyUI cards, checkboxes, and buttons
      this.instance = new PrivacySettings(this.host, {
        ...(this.cachedConsent !== undefined && { initialConsent: this.cachedConsent }),
        onConsentChange: (snapshot) => {
          this.cachedConsent = snapshot;
          this.persistConsent(snapshot);
        }
      });
      if (this.messages) {
        this.instance.setMessages(this.messages);
      }
      this.instance.render();
    } catch (error) {
      console.error('[PrivacySection] Failed to render privacy settings:', error);
      this.host.textContent =
        this.messages?.privacySettingsError ?? 'Failed to save settings, please try again.';
    }
  }

  private subscribeToRepository(): void {
    this.unsubscribeFromRepo?.();
    this.unsubscribeFromRepo = this.optionsRepo.onChange((options) => {
      const snapshot = this.extractConsentSnapshot(
        options as Partial<{ privacyPreferences?: PrivacyConsentSnapshot }>
      );
      if (snapshot) {
        this.cachedConsent = snapshot;
        this.instance?.applyConsentSnapshot(snapshot);
      }
    });
  }

  private extractConsentSnapshot(
    options: Partial<{ privacyPreferences?: PrivacyConsentSnapshot }>
  ): PrivacyConsentSnapshot | null {
    return options.privacyPreferences ?? null;
  }

  private persistConsent(snapshot: PrivacyConsentSnapshot): void {
    void persistPrivacyConsentAction(snapshot, {
      optionsRepository: this.optionsRepo
    })
      .catch((error) => {
        console.error(
          '[PrivacySection] Failed to persist privacy preferences via repository:',
          error
        );
      });
  }
}

import type { CompleteOptions, StoredOptions, TemplateOptions } from '@shared/types/options';
import type { IOptionsRepository } from '@shared/repositories';
import { resolveRepository } from '@shared/di/serviceRegistry';
import { DI_TOKENS } from '@shared/di/tokens';
import { configProvider } from '@shared/config';
import { DEFAULT_DOMAIN_MAPPINGS } from '../../utils/defaults';
import { getOptionsController, markPendingAutoSave } from '../../app/optionsControllerContext';
import { DomainMappingsController } from '../controls/domainMappings';
import {
  createReadingTemplateController,
  type ReadingTemplateController
} from '../controls/readingTemplateControls';
import { type FormSectionHandlers } from '../formSections/formSectionManager';
import { UiButton as DaisyButton } from '@ui/primitives/button';
import { DaisyCard } from '@ui/primitives/card';
import { UiInput as DaisyInput } from '@ui/primitives/input';
import { createOptionsHintText } from '@ui/primitives/layout';
import { createSelectElement as createDaisySelectElement } from '@ui/primitives/select';
import type { SectionRenderContext } from './BaseSection';
import { BaseSection } from './BaseSection';

const TEMPLATE_DEFAULTS = configProvider.getTemplates();

interface EventBinding {
  target: EventTarget;
  type: string;
  handler: EventListener;
}

const resolveTemplateValue = (
  current: string | undefined,
  previous: string | undefined,
  fallback: string
): string => {
  const trimmed = current?.trim() ?? '';
  if (trimmed) {
    return trimmed;
  }
  if (previous && previous.trim().length > 0) {
    return previous;
  }
  return fallback;
};

export class TemplatesSection extends BaseSection<SectionRenderContext> {
  private readonly optionsRepo: IOptionsRepository;
  private articleInput: HTMLInputElement | null = null;
  private fragmentInput: HTMLInputElement | null = null;
  private aiInput: HTMLInputElement | null = null;
  private readingModeSelect: HTMLSelectElement | null = null;
  private readingCustomInput: HTMLInputElement | null = null;
  private domainMappingsHost: HTMLElement | null = null;

  private readingController: ReadingTemplateController | null = null;
  private domainMappingsController: DomainMappingsController | null = null;
  private eventBindings: EventBinding[] = [];
  private unsubscribeRepo: (() => void) | null = null;

  constructor(container: HTMLElement, optionsRepo: IOptionsRepository) {
    super(container);
    this.optionsRepo = optionsRepo;
  }

  protected renderWithState(_context: SectionRenderContext): HTMLElement {
    this.disposeControllers();
    this.applySectionChrome(['transition-opacity', 'duration-200']);

    const header = this.buildHeader();
    const body = this.buildBody();

    this.container.replaceChildren(header, body);
    this.setupControllers();
    this.applyInitialSnapshot();
    this.registerFormIntegration();
    this.subscribeToRepository();
    return this.container;
  }

  override destroy(): void {
    this.disposeControllers();
    this.unregisterManagedFormSection();
    this.unsubscribeRepo?.();
    this.unsubscribeRepo = null;
    super.destroy();
  }

  private buildHeader(): HTMLElement {
    return this.buildSectionHeader({
      title: this.messages?.templateConfigTitle ?? '文章、视频路径配置',
      description: this.messages?.templateConfigHint ?? '为不同类型的剪藏指定文件命名'
    });
  }

  private buildBody(): HTMLElement {
    const body = this.createSectionBody();
    body.append(this.buildTemplateSettings(), this.buildDomainMappingsSection());
    return body;
  }

  private buildTemplateSettings(): HTMLElement {
    const settings = this.createSectionSettings();

    const articleSetting = this.createSettingRow();
    const articleLabel = this.createElement('div', 'text-sm font-medium text-base-content/60');
    articleLabel.textContent = this.messages?.articleTemplateLabel ?? '文章、视频路径模板';
    const articleControl = this.createElement('div', 'flex flex-wrap justify-start gap-2');
    const articleHost = this.createElement('div', 'w-full');
    // ✅ Stage 3 Week 4: Migrated article template input to DaisyInput (TemplatesSection)
    const articleInput = new DaisyInput(articleHost).render({
      type: 'text',
      variant: 'bordered',
      size: 'md',
      placeholder: 'Articles/{domain}/{yyyy}/{slug}.md'
    });
    articleInput.dataset.templateRole = 'article';
    articleControl.append(articleHost);
    this.articleInput = articleInput;
    this.bindEvent(articleInput, 'input', this.handleFieldChanged);
    const articleVars = this.buildTemplateVars();
    const articleHint = createOptionsHintText({ tag: 'div' });
    articleHint.textContent =
      this.messages?.templateVariableNote ??
      '{slug} 表示标题的短链写法；{HHmmss}/{HHmm} 可插入保存时间，{mm} 仍代表月份。';
    articleSetting.append(articleLabel, articleControl, articleVars, articleHint);
    settings.append(articleSetting);

    const fragmentSetting = this.createSettingRow();
    const fragmentLabel = this.createElement('div', 'text-sm font-medium text-base-content/60');
    fragmentLabel.textContent = this.messages?.fragmentTemplateLabel ?? '片段路径模板';
    const fragmentControl = this.createElement('div', 'flex flex-wrap justify-start gap-2');
    const fragmentHost = this.createElement('div', 'w-full');
    // ✅ Stage 3 Week 4: Migrated fragment template input to DaisyInput (TemplatesSection)
    const fragmentInput = new DaisyInput(fragmentHost).render({
      type: 'text',
      variant: 'bordered',
      size: 'md',
      placeholder: 'Clippings/{domain}/{yyyy}/{yyyy}-{mm}-{dd}/{slug}.md'
    });
    fragmentInput.dataset.templateRole = 'fragment';
    fragmentControl.append(fragmentHost);
    this.fragmentInput = fragmentInput;
    this.bindEvent(fragmentInput, 'input', this.handleFieldChanged);
    fragmentSetting.append(fragmentLabel, fragmentControl, this.buildTemplateVars());
    settings.append(fragmentSetting);

    const readingSetting = this.createSettingRow();
    const readingLabel = this.createElement('div', 'text-sm font-medium text-base-content/60');
    readingLabel.textContent = this.messages?.readingTemplateLabel ?? '阅读模式路径模板';
    const readingControl = this.createElement('div', 'flex flex-wrap justify-start gap-2');
    const readingSelect = createDaisySelectElement({
      className: 'w-full',
      options: [
        {
          value: 'article',
          label: this.messages?.readingTemplateOptionArticle ?? '与文章路径相同'
        },
        {
          value: 'fragment',
          label: this.messages?.readingTemplateOptionFragment ?? '与片段路径相同'
        },
        {
          value: 'custom',
          label: this.messages?.readingTemplateOptionCustom ?? '自定义'
        }
      ]
    });
    const readingInputHost = this.createElement('div', 'w-full');
    // ✅ Stage 3 Week 4: Migrated reading template input to DaisyInput (TemplatesSection)
    const readingInput = new DaisyInput(readingInputHost).render({
      type: 'text',
      variant: 'bordered',
      size: 'md',
      placeholder: 'Reading/{domain}/{yyyy}/{yyyy}-{mm}-{dd}/{slug}.md',
      disabled: true
    });
    readingInput.dataset.templateRole = 'reading-custom';
    readingSelect.dataset.templateRole = 'reading-mode';
    readingControl.append(readingSelect, readingInputHost);
    readingSetting.append(readingLabel, readingControl);
    this.readingModeSelect = readingSelect;
    this.readingCustomInput = readingInput;
    settings.append(readingSetting);

    const aiSetting = this.createSettingRow();
    const aiLabel = this.createElement('div', 'text-sm font-medium text-base-content/60');
    aiLabel.textContent = this.messages?.aiTemplateLabel ?? 'AI 对话路径模板';
    const aiControl = this.createElement('div', 'flex flex-wrap justify-start gap-2');
    const aiHost = this.createElement('div', 'w-full');
    const aiInput = new DaisyInput(aiHost).render({
      type: 'text',
      variant: 'bordered',
      size: 'md',
      placeholder: 'AI/{platform}/{yyyy}/{yyyy}-{mm}-{dd}_{title}.md'
    });
    aiInput.dataset.templateRole = 'ai';
    aiControl.append(aiHost);
    this.aiInput = aiInput;
    this.bindEvent(aiInput, 'input', this.handleFieldChanged);
    aiSetting.append(aiLabel, aiControl, this.buildTemplateVars());
    settings.append(aiSetting);

    return settings;
  }

  private buildDomainMappingsSection(): HTMLElement {
    const host = this.createElement('div');
    const body = this.createElement('div', 'space-y-3');
    const hint = this.createElement('div', 'text-sm text-base-content/60');
    hint.textContent =
      this.messages?.domainMappingHint ??
      '为常见站点配置更友好的名称，例如将 mp.weixin.qq.com 映射为 “公众号”。';

    const listContainer = this.createElement('div', 'grid gap-2');
    this.domainMappingsHost = listContainer;
    body.append(hint, listContainer);

    const addButtonHost = this.createElement('div');
    new DaisyButton(addButtonHost).render({
      label: this.messages?.addMappingButton ?? '+ 添加映射',
      variant: 'primary',
      size: 'sm',
      iconName: 'Plus',
      onClick: this.handleAddMappingClick
    });

    const card = new DaisyCard(host);
    card.render({
      title: this.messages?.domainMappingTitle ?? '域名映射配置',
      body,
      actions: [addButtonHost]
    });
    // ⏸️ Stage 3 Month 3: Template/domain mapping drag handles pending Zag.js list integration
    return host;
  }

  private setupControllers(): void {
    if (this.readingController) {
      this.readingController.dispose();
    }
    if (
      this.readingModeSelect &&
      this.readingCustomInput &&
      this.articleInput &&
      this.fragmentInput
    ) {
      this.readingController = createReadingTemplateController(
        {
          modeSelect: this.readingModeSelect,
          customInput: this.readingCustomInput,
          articleInput: this.articleInput,
          fragmentInput: this.fragmentInput,
          onChange: this.handleFieldChanged
        },
        {
          defaultTemplate: TEMPLATE_DEFAULTS.reading,
          articleDefault: TEMPLATE_DEFAULTS.article,
          fragmentDefault: TEMPLATE_DEFAULTS.fragment
        }
      );
    }

    if (this.domainMappingsController) {
      this.domainMappingsController.dispose();
    }
    if (this.domainMappingsHost) {
      this.domainMappingsController = new DomainMappingsController(this.domainMappingsHost);
      if (this.messages) {
        this.domainMappingsController.setMessages(this.messages);
      }
      this.domainMappingsController.render({
        maxEmptyRows: 3,
        onChange: this.handleFieldChanged
      });
    }
  }

  private registerFormIntegration(): void {
    const binding: FormSectionHandlers = {
      applySnapshot: (options) => {
        this.applySnapshot(options);
      },
      collectChanges: (previous) => this.collectChanges(previous)
    };
    this.registerManagedFormSection('templates', binding);
  }

  private applyInitialSnapshot(): void {
    const defaultsOnly: StoredOptions = {
      templates: { ...TEMPLATE_DEFAULTS },
      domainMappings: { ...DEFAULT_DOMAIN_MAPPINGS }
    } as StoredOptions;
    this.applySnapshot(defaultsOnly);
  }

  private applySnapshot(options: StoredOptions): void {
    const templates = (options.templates ?? {}) as Partial<TemplateOptions>;

    if (this.articleInput) {
      this.articleInput.value = templates.article ?? TEMPLATE_DEFAULTS.article;
    }
    if (this.fragmentInput) {
      this.fragmentInput.value = templates.fragment ?? TEMPLATE_DEFAULTS.fragment;
    }
    if (this.aiInput) {
      this.aiInput.value = templates.ai ?? TEMPLATE_DEFAULTS.ai;
    }

    this.readingController?.apply(templates.reading ?? undefined);

    const mappings =
      options.domainMappings && Object.keys(options.domainMappings).length > 0
        ? { ...options.domainMappings }
        : { ...DEFAULT_DOMAIN_MAPPINGS };
    this.domainMappingsController?.setMappings(mappings);
  }

  private collectChanges(previous: StoredOptions | null): Partial<CompleteOptions> {
    const previousTemplates = previous?.templates;
    const previousMappings = previous?.domainMappings ?? null;

    const article = resolveTemplateValue(
      this.articleInput?.value,
      previousTemplates?.article,
      TEMPLATE_DEFAULTS.article
    );
    const fragment = resolveTemplateValue(
      this.fragmentInput?.value,
      previousTemplates?.fragment,
      TEMPLATE_DEFAULTS.fragment
    );
    const readingCollected = this.readingController?.collect() ?? '';
    const reading = resolveTemplateValue(
      readingCollected,
      previousTemplates?.reading,
      TEMPLATE_DEFAULTS.reading
    );
    const ai = resolveTemplateValue(
      this.aiInput?.value,
      previousTemplates?.ai,
      TEMPLATE_DEFAULTS.ai
    );

    const collectedMappings = this.domainMappingsController?.collect() ?? {};
    const finalMappings =
      Object.keys(collectedMappings).length > 0
        ? collectedMappings
        : previousMappings && Object.keys(previousMappings).length > 0
          ? { ...previousMappings }
          : { ...DEFAULT_DOMAIN_MAPPINGS };

    const partial: Partial<CompleteOptions> = {
      templates: {
        article,
        fragment,
        reading,
        ai
      },
      domainMappings: { ...finalMappings }
    };
    return partial;
  }

  private buildTemplateVars(): HTMLElement {
    const wrapper = this.createElement('div', 'mt-2 text-xs text-base-content/60 break-all');
    wrapper.textContent = `${this.messages?.availableVariables ?? '可用变量：'} `;
    [
      '{platform}',
      '{domain}',
      '{yyyy}',
      '{mm}',
      '{dd}',
      '{HHmmss}',
      '{HHmm}',
      '{HH}',
      '{ss}',
      '{slug}',
      '{title}'
    ].forEach((token) => {
      const code = document.createElement('code');
      code.className =
        'mx-1 px-1 py-0.5 rounded bg-base-200 border border-base-300/50 font-mono text-[10px] text-accent';
      code.textContent = token;
      wrapper.append(code);
    });
    return wrapper;
  }

  private handleAddMappingClick = (): void => {
    this.domainMappingsController?.addRow('', '', { autoFocus: true });
  };

  private handleFieldChanged = (): void => {
    markPendingAutoSave('templates');
    const controller = getOptionsController();
    controller?.scheduleAutoSave();
  };

  private bindEvent(target: EventTarget, type: string, handler: EventListener): void {
    target.addEventListener(type, handler);
    this.eventBindings.push({ target, type, handler });
  }

  private disposeControllers(): void {
    this.eventBindings.forEach(({ target, type, handler }) => {
      target.removeEventListener(type, handler);
    });
    this.eventBindings = [];

    this.readingController?.dispose();
    this.readingController = null;

    this.domainMappingsController?.dispose();
    this.domainMappingsController = null;
  }

  private subscribeToRepository(): void {
    this.unsubscribeRepo?.();
    this.unsubscribeRepo = this.optionsRepo.onChange((options) => {
      this.applySnapshot(options);
    });
  }
}

import { resolveRepository } from '@shared/di/serviceRegistry';
import { DI_TOKENS } from '@shared/di/tokens';
import type { IOptionsRepository } from '@shared/repositories';
import type { SectionRenderContext } from './BaseSection';
import { BaseSection } from './BaseSection';
import { createOptionsButtonElement as createDaisyButtonElement } from '@ui/primitives/button';
import { UiAlert as DaisyAlert } from '@ui/primitives/alert';
import {
  copyConfig as copyConfigAction,
  importConfig as importConfigAction
} from '../../app/optionsActions';
import { persistTransferLogAction } from '../../app/actions';

interface TransferLogSnapshot {
  transferLog?: {
    lastAction: 'copy' | 'import';
    timestamp: number;
  };
}

export class TransferSection extends BaseSection<SectionRenderContext> {
  private readonly optionsRepo: IOptionsRepository;
  private copyButton: HTMLButtonElement | null = null;
  private importButton: HTMLButtonElement | null = null;
  private messageArea: HTMLElement | null = null;
  private messageHideTimer: ReturnType<typeof setTimeout> | null = null;
  private isCopying = false;
  private isImporting = false;
  private repoUnsubscribe: (() => void) | null = null;
  private cachedTransferLog: TransferLogSnapshot['transferLog'] | null = null;

  constructor(container: HTMLElement, optionsRepo: IOptionsRepository) {
    super(container);
    this.optionsRepo = optionsRepo;
  }

  protected renderWithState(): HTMLElement {
    this.applySectionChrome();
    const header = this.buildHeader();
    const body = this.buildBody();

    this.container.replaceChildren(header, body);
    this.subscribeToRepository();
    return this.container;
  }

  override destroy(): void {
    this.copyButton?.removeEventListener('click', this.handleCopy);
    this.importButton?.removeEventListener('click', this.handleImport);
    this.copyButton = null;
    this.importButton = null;
    this.messageArea = null;
    if (this.messageHideTimer) {
      clearTimeout(this.messageHideTimer);
      this.messageHideTimer = null;
    }
    this.repoUnsubscribe?.();
    this.repoUnsubscribe = null;
    super.destroy();
  }

  private buildHeader(): HTMLElement {
    return this.buildSectionHeader({
      title: this.messages?.configTransferTitle ?? '配置同步',
      description: this.messages?.configTransferHint ?? '在不同浏览器之间复制配置，快速完成同步',
      titleClassName: 'm-0 text-2xl font-semibold tracking-tight',
      descriptionClassName: 'text-base-content/60 text-md'
    });
  }

  private buildBody(): HTMLElement {
    const wrapper = this.createSectionBody();

    wrapper.append(this.buildActionRow());
    wrapper.append(this.buildMessageArea());

    return wrapper;
  }

  private buildActionRow(): HTMLElement {
    const actionRow = this.createElement('div', 'flex flex-wrap gap-3 items-center mt-4');

    const copyButton = createDaisyButtonElement({
      label: this.messages?.copyConfigButton ?? '复制配置',
      variant: 'primary',
      id: 'copyConfigBtn'
    });
    copyButton.addEventListener('click', this.handleCopy);

    const importButton = createDaisyButtonElement({
      label: this.messages?.importConfigButton ?? '导入并保存',
      variant: 'outline',
      id: 'importConfigBtn'
    });
    importButton.addEventListener('click', this.handleImport);

    this.copyButton = copyButton;
    this.importButton = importButton;

    actionRow.append(copyButton, importButton);
    return actionRow;
  }

  private buildMessageArea(): HTMLElement {
    const messageArea = this.createElement('div', 'my-3 w-full');
    messageArea.id = 'transferMessage';
    messageArea.hidden = true;
    this.messageArea = messageArea;
    return messageArea;
  }

  private showMessage(text: string, isError = false, options: { persist?: boolean } = {}): void {
    if (!this.messageArea) {
      return;
    }
    this.messageArea.hidden = false;
    const alert = new DaisyAlert(this.messageArea);
    // ✅ Stage 3 Week 2: Migrated transfer status to DaisyAlert
    alert.render({
      type: isError ? 'error' : 'success',
      message: text,
      dismissible: true,
      onDismiss: () => {
        if (this.messageArea) {
          this.messageArea.hidden = true;
          this.messageArea.replaceChildren();
        }
      }
    });

    if (this.messageHideTimer) {
      clearTimeout(this.messageHideTimer);
    }
    if (options.persist) {
      this.messageHideTimer = null;
      return;
    }
    this.messageHideTimer = setTimeout(() => {
      if (this.messageArea) {
        this.messageArea.hidden = true;
        this.messageArea.replaceChildren();
      }
      this.messageHideTimer = null;
    }, 5000);
  }

  private handleCopy = (): void => {
    if (this.isCopying || !this.copyButton) {
      return;
    }

    this.isCopying = true;
    this.copyButton.disabled = true;
    this.copyButton.setAttribute('aria-busy', 'true');

    void copyConfigAction()
      .then(() => {
        this.persistTransferLog('copy');
        this.showMessage(this.messages?.copyConfigSuccess ?? '配置已复制到剪贴板！');
      })
      .catch((error) => {
        this.showMessage(`Copy failed: ${String(error)}`, true);
      })
      .finally(() => {
        if (this.copyButton) {
          this.copyButton.disabled = false;
          this.copyButton.removeAttribute('aria-busy');
        }
        this.isCopying = false;
      });
  };

  private handleImport = (): void => {
    if (this.isImporting || !this.importButton) {
      return;
    }

    this.isImporting = true;
    this.importButton.disabled = true;
    this.importButton.setAttribute('aria-busy', 'true');

    void importConfigAction()
      .then(() => {
        this.persistTransferLog('import');
        this.showMessage(this.messages?.importSuccess ?? '配置已成功导入！');
      })
      .catch((error) => {
        this.showMessage(`Import failed: ${String(error)}`, true);
      })
      .finally(() => {
        if (this.importButton) {
          this.importButton.disabled = false;
          this.importButton.removeAttribute('aria-busy');
        }
        this.isImporting = false;
      });
  };

  private subscribeToRepository(): void {
    this.repoUnsubscribe?.();
    this.repoUnsubscribe = this.optionsRepo.onChange((options) => {
      const snapshot = (options as Partial<TransferLogSnapshot>).transferLog ?? null;
      this.cachedTransferLog = snapshot;
      if (snapshot) {
        this.showHistoryMessage(snapshot);
      }
    });
  }

  private showHistoryMessage(log: NonNullable<TransferLogSnapshot['transferLog']>): void {
    const date = new Date(log.timestamp).toLocaleString();
    const text =
      log.lastAction === 'copy'
        ? (this.messages?.copyConfigSuccess ?? '配置已复制到剪贴板！')
        : (this.messages?.importSuccess ?? '配置已成功导入！');
    this.showMessage(`${text} (${date})`, false, { persist: true });
  }

  private persistTransferLog(lastAction: 'copy' | 'import'): void {
    void persistTransferLogAction(lastAction, {
      optionsRepository: this.optionsRepo,
      now: Date.now
    })
      .then((entry) => {
        this.cachedTransferLog = entry;
      })
      .catch((error) => {
        console.error('[TransferSection] Failed to persist transfer log via repository:', error);
      });
  }
}

import type { CompleteOptions, StoredOptions } from '@shared/types/options';
import type { IOptionsRepository } from '@shared/repositories';
import { resolveRepository } from '@shared/di/serviceRegistry';
import { DI_TOKENS } from '@shared/di/tokens';
import { DEFAULT_OPTIONS } from '@shared/config';
import { getOptionsController, markPendingAutoSave } from '../../app/optionsControllerContext';
import { type FormSectionHandlers } from '../formSections/formSectionManager';
import { UiButton as DaisyButton } from '@ui/primitives/button';
import { DaisyCard } from '@ui/primitives/card';
import { UiCheckbox as DaisyCheckbox } from '@ui/primitives/checkbox';
import { UiInput as DaisyInput } from '@ui/primitives/input';
import type { SectionRenderContext } from './BaseSection';
import { BaseSection } from './BaseSection';

const VIDEO_DEFAULTS = DEFAULT_OPTIONS.video ?? {
  floatingPromptEnabled: true,
  promptButtonLabel: '开启视频笔记',
  promptShortcut: 'Alt+V'
};
const SUPPORTED_VIDEO_PLATFORMS = ['youtube', 'bilibili'] as const;

export class VideoSection extends BaseSection<SectionRenderContext> {
  private readonly optionsRepo: IOptionsRepository;
  private floatingPromptToggle: HTMLInputElement | null = null;
  private promptLabelInput: HTMLInputElement | null = null;
  private promptShortcutInput: HTMLInputElement | null = null;
  private unsubscribeRepo: (() => void) | null = null;

  private readonly handleToggleChange = (): void => {
    markPendingAutoSave('video');
    const controller = getOptionsController();
    controller?.scheduleAutoSave();
  };

  private readonly handlePromptInputChange = (): void => {
    markPendingAutoSave('video');
    const controller = getOptionsController();
    controller?.scheduleAutoSave();
  };

  constructor(container: HTMLElement, optionsRepo: IOptionsRepository) {
    super(container);
    this.optionsRepo = optionsRepo;
  }

  protected renderWithState(): HTMLElement {
    this.applySectionChrome();
    const header = this.buildHeader();
    const body = this.buildBody();

    this.container.replaceChildren(header, body);
    this.registerFormIntegration();
    this.subscribeToRepository();
    return this.container;
  }

  override destroy(): void {
    if (this.floatingPromptToggle) {
      this.floatingPromptToggle.removeEventListener('change', this.handleToggleChange);
      this.floatingPromptToggle = null;
    }
    this.promptLabelInput = null;
    this.promptShortcutInput = null;

    this.unregisterManagedFormSection();
    this.unsubscribeRepo?.();
    this.unsubscribeRepo = null;

    super.destroy();
  }

  private buildHeader(): HTMLElement {
    return this.buildSectionHeader({
      title: this.messages?.videoConfigTitle ?? '视频模式',
      description: this.messages?.videoConfigHint ?? '可在视频网站自动提示进入视频笔记模式',
      titleClassName: 'm-0 text-2xl font-semibold tracking-tight',
      descriptionClassName: 'text-base-content/60 text-md'
    });
  }

  private buildBody(): HTMLElement {
    const wrapper = this.createSectionBody();
    const settings = this.createSectionSettings();

    settings.append(
      this.buildFloatingPromptSetting(),
      this.buildPromptCustomizationSetting(),
      this.buildSupportedPlatformsCard(),
      this.buildActionRow()
    );
    wrapper.append(settings);
    return wrapper;
  }

  private buildFloatingPromptSetting(): HTMLElement {
    const setting = this.createElement(
      'div',
      'grid grid-cols-[minmax(0,1fr)] gap-3 py-4 border-t border-base-300 items-start first:border-t-0 first:pt-0'
    );
    const control = this.createElement('div', 'flex flex-wrap justify-start gap-2');
    const checkboxHost = this.createElement('div');
    const checkboxComponent = new DaisyCheckbox(checkboxHost);
    const checkbox = checkboxComponent.render({
      id: 'videoFloatingPrompt',
      label: this.messages?.videoFloatingPromptLabel ?? '在视频网站显示浮动提示按钮'
    });
    control.append(checkboxHost);

    const hint = this.createElement('div', 'w-full text-xs text-base-content/60 mt-1');
    hint.textContent =
      this.messages?.videoFloatingPromptHint ??
      '支持 YouTube 与哔哩哔哩，默认在右下角显示提醒，点击即可开启视频模式。';

    checkbox.addEventListener('change', this.handleToggleChange);
    this.floatingPromptToggle = checkbox;

    setting.append(control, hint);
    return setting;
  }

  private buildPromptCustomizationSetting(): HTMLElement {
    const setting = this.createSettingRow();
    const label = this.createElement('div', 'text-sm text-base-content/60 font-semibold');
    label.textContent = this.messages?.videoPromptCustomizationTitle ?? '浮动提示文案与快捷键';

    const controls = this.createElement('div', 'grid gap-4 lg:grid-cols-2');

    const promptLabelControl = this.createElement('div', 'flex flex-col gap-2');
    const promptLabelTitle = this.createElement('div', 'text-sm font-medium text-base-content');
    promptLabelTitle.textContent = this.messages?.videoPromptLabelTitle ?? '提示按钮文案';
    const labelInputHost = this.createElement('div', 'w-full');
    // ✅ Stage 3 Week 3: Migrated video prompt label to DaisyInput (VideoSection)
    const labelInput = new DaisyInput(labelInputHost).render({
      type: 'text',
      variant: 'bordered',
      size: 'md',
      placeholder: this.messages?.videoPromptLabelPlaceholder ?? '例如：开启视频笔记',
      value: VIDEO_DEFAULTS.promptButtonLabel,
      onChange: () => this.handlePromptInputChange(),
      onBlur: (value) => {
        if (this.promptLabelInput) {
          this.promptLabelInput.value = this.resolvePromptLabel(value);
        }
      }
    });
    labelInput.id = 'videoPromptLabel';
    this.promptLabelInput = labelInput;
    promptLabelControl.append(promptLabelTitle, labelInputHost);
    const promptLabelHint = this.createElement('p', 'text-xs text-base-content/60 m-0');
    promptLabelHint.textContent =
      this.messages?.videoPromptLabelHint ??
      '将显示在浮动按钮的 aria-label，用于屏幕阅读器与悬浮提示。';
    promptLabelControl.append(promptLabelHint);

    const shortcutControl = this.createElement('div', 'flex flex-col gap-2');
    const shortcutTitle = this.createElement('div', 'text-sm font-medium text-base-content');
    shortcutTitle.textContent = this.messages?.videoPromptShortcutTitle ?? '提示快捷键';
    const shortcutInputHost = this.createElement('div', 'w-full');
    // ✅ Stage 3 Week 3: Migrated video shortcut input to DaisyInput (VideoSection)
    const shortcutInput = new DaisyInput(shortcutInputHost).render({
      type: 'text',
      variant: 'bordered',
      size: 'md',
      placeholder: this.messages?.videoPromptShortcutPlaceholder ?? '例如：Alt+V',
      value: VIDEO_DEFAULTS.promptShortcut,
      onChange: () => this.handlePromptInputChange(),
      onBlur: (value) => {
        if (this.promptShortcutInput) {
          this.promptShortcutInput.value = this.resolvePromptShortcut(value);
        }
      }
    });
    shortcutInput.id = 'videoPromptShortcut';
    this.promptShortcutInput = shortcutInput;
    shortcutControl.append(shortcutTitle, shortcutInputHost);
    const shortcutHint = this.createElement('p', 'text-xs text-base-content/60 m-0');
    shortcutHint.textContent =
      this.messages?.videoPromptShortcutHint ??
      '会显示在悬浮提示中，建议使用 Alt/Cmd 组合键，便于记忆。';
    shortcutControl.append(shortcutHint);

    controls.append(promptLabelControl, shortcutControl);
    setting.append(label, controls);
    return setting;
  }

  private buildSupportedPlatformsCard(): HTMLElement {
    const host = this.createElement('div', 'w-full');
    const card = new DaisyCard(host);
    const body = this.createElement('div', 'space-y-3');
    const list = this.createElement('ul', 'list-none p-0 m-0 space-y-3');
    for (const platform of SUPPORTED_VIDEO_PLATFORMS) {
      const platformText = this.resolvePlatformText(platform);
      const item = this.createElement(
        'li',
        ['flex', 'flex-col', 'gap-1', 'border', 'border-base-300', 'rounded-lg', 'p-3'].join(' ')
      );
      const title = this.createElement(
        'span',
        ['text-sm', 'font-semibold', 'text-base-content', 'flex', 'items-center', 'gap-2'].join(' ')
      );
      title.textContent = platformText.name;
      const badge = this.createElement(
        'span',
        [
          'text-[11px]',
          'uppercase',
          'tracking-wide',
          'bg-base-200',
          'text-base-content/70',
          'px-2',
          'py-0.5',
          'rounded-full'
        ].join(' ')
      );
      badge.textContent = this.messages?.videoPlatformSupportedBadge ?? 'SUPPORTED';
      title.append(badge);
      const description = this.createElement(
        'p',
        'text-xs text-base-content/70 m-0 leading-relaxed'
      );
      description.textContent = platformText.description;
      item.append(title, description);
      list.append(item);
    }
    body.append(list);
    card.render({
      title: this.messages?.videoSupportedPlatformsTitle ?? '已适配平台',
      body
    });
    return host;
  }

  private buildActionRow(): HTMLElement {
    const actions = this.createElement(
      'div',
      ['flex', 'flex-wrap', 'gap-3', 'items-center', 'border-t', 'border-base-300', 'pt-4'].join(
        ' '
      )
    );

    const enableHost = this.createElement('div');
    new DaisyButton(enableHost).render({
      label: this.messages?.videoEnableButton ?? '启用视频笔记',
      variant: 'primary',
      size: 'sm',
      iconName: 'Play',
      onClick: () => {
        if (this.floatingPromptToggle) {
          this.floatingPromptToggle.checked = true;
        }
        this.handleToggleChange();
      }
    });

    const saveHost = this.createElement('div');
    new DaisyButton(saveHost).render({
      label: this.messages?.videoSaveConfigButton ?? '保存视频配置',
      variant: 'secondary',
      size: 'sm',
      iconName: 'Save',
      onClick: () => {
        const controller = getOptionsController();
        controller?.scheduleAutoSave();
      }
    });

    actions.append(enableHost, saveHost);
    return actions;
  }

  private resolvePlatformText(platform: (typeof SUPPORTED_VIDEO_PLATFORMS)[number]): {
    name: string;
    description: string;
  } {
    if (platform === 'youtube') {
      return {
        name: this.messages?.videoPlatformYoutubeName ?? 'YouTube',
        description:
          this.messages?.videoPlatformYoutubeDescription ??
          '支持 watch / short 页面，自动识别浮动提示按钮，点击即可进入视频笔记模式。'
      };
    }

    return {
      name: this.messages?.videoPlatformBilibiliName ?? '哔哩哔哩',
      description:
        this.messages?.videoPlatformBilibiliDescription ??
        '支持 BV/AV 视频页，保留弹幕区域空间并附带快捷键提示。'
    };
  }

  private applySnapshot(options: StoredOptions): void {
    const video = options.video;
    if (this.floatingPromptToggle) {
      this.floatingPromptToggle.checked = video?.floatingPromptEnabled ?? true;
    }
    if (this.promptLabelInput) {
      this.promptLabelInput.value = this.resolvePromptLabel(video?.promptButtonLabel);
    }
    if (this.promptShortcutInput) {
      this.promptShortcutInput.value = this.resolvePromptShortcut(video?.promptShortcut);
    }
  }

  private collectChanges(previous: StoredOptions | null): Partial<CompleteOptions> {
    const previousVideo = previous?.video;
    const floatingPromptEnabled =
      this.floatingPromptToggle?.checked ?? previousVideo?.floatingPromptEnabled ?? true;
    const promptButtonLabel = this.resolvePromptLabel(
      this.promptLabelInput?.value ?? previousVideo?.promptButtonLabel
    );
    const promptShortcut = this.resolvePromptShortcut(
      this.promptShortcutInput?.value ?? previousVideo?.promptShortcut
    );

    const partial: Partial<CompleteOptions> = {
      video: {
        floatingPromptEnabled,
        promptButtonLabel,
        promptShortcut,
        controlBarAutoPause: previousVideo?.controlBarAutoPause ?? true,
        controlBarScreenshot: previousVideo?.controlBarScreenshot ?? true
      }
    };
    return partial;
  }

  private registerFormIntegration(): void {
    const binding: FormSectionHandlers = {
      applySnapshot: (options) => {
        this.applySnapshot(options);
      },
      collectChanges: (previous) => this.collectChanges(previous)
    };
    this.registerManagedFormSection('video', binding);
  }

  private resolvePromptLabel(input?: string): string {
    const trimmed = input?.trim();
    return trimmed && trimmed.length > 0 ? trimmed : VIDEO_DEFAULTS.promptButtonLabel;
  }

  private resolvePromptShortcut(input?: string): string {
    const trimmed = input?.trim();
    const normalized = trimmed ? trimmed.toUpperCase() : '';
    return normalized.length > 0 ? normalized : VIDEO_DEFAULTS.promptShortcut;
  }

  private subscribeToRepository(): void {
    this.unsubscribeRepo?.();
    this.unsubscribeRepo = this.optionsRepo.onChange((options) => {
      this.applySnapshot(options);
    });
  }
}

import type { CompleteOptions, StoredOptions } from '@shared/types/options';
import type { YamlConfigOverrides, YamlContentType } from '@shared/types/yamlConfig';
import type { IYamlRepository } from '@shared/repositories/IYamlRepository';
import { YamlConfigService } from '@shared/services/yamlConfigService';
import { resolveRepository } from '@shared/di/serviceRegistry';
import { DI_TOKENS } from '@shared/di/tokens';
import { getOptionsController, markPendingAutoSave } from '../../app/optionsControllerContext';
import { type FormSectionHandlers } from '../formSections/formSectionManager';
import type { YamlConfigView } from '@ui/domains/yaml-config';
import type { SectionRenderContext } from './BaseSection';
import { BaseSection } from './BaseSection';

const CONTENT_TYPE_ORDER: YamlContentType[] = ['article', 'clipper', 'video', 'ai_chat'];

interface YamlSectionDependencies {
  yamlRepository: IYamlRepository;
  yamlService?: YamlConfigService;
}

export class YamlConfigSection extends BaseSection<SectionRenderContext> {
  private yamlView: YamlConfigView | null = null;
  private yamlViewModulePromise: Promise<typeof import('@ui/domains/yaml-config')> | null = null;
  private readonly yamlRepository: IYamlRepository;
  private readonly yamlService: YamlConfigService;
  private unsubscribeYamlRepo: (() => void) | null = null;
  private currentOverrides: YamlConfigOverrides | null = null;
  private lastRenderedSerialized: string | null = null;
  private summaryEl: HTMLDivElement | null = null;
  private suppressRepoRender = false;

  constructor(container: HTMLElement, deps: YamlSectionDependencies) {
    super(container);
    this.yamlRepository = deps.yamlRepository;
    this.yamlService = deps.yamlService ?? new YamlConfigService();
  }

  protected override renderWithState(_context: SectionRenderContext): HTMLElement {
    this.disposeView();
    this.applySectionChrome();
    this.container.replaceChildren(this.buildHeader(), this.buildBody());
    void this.initializeYamlView();
    this.ensureYamlSubscription();
    void this.bootstrapOverrides();
    this.registerFormIntegration();
    return this.container;
  }

  override destroy(): void {
    this.unregisterManagedFormSection();
    if (this.unsubscribeYamlRepo) {
      this.unsubscribeYamlRepo();
      this.unsubscribeYamlRepo = null;
    }
    this.disposeView();
    super.destroy();
  }

  private async initializeYamlView(): Promise<void> {
    const host = this.container.querySelector<HTMLElement>('#yamlConfigViewHost');
    if (!host) {
      console.warn('[YamlConfigSection] Missing YAML config view host, view not initialized.');
      return;
    }

    const { YamlConfigView } = await this.loadYamlViewModule();
    this.yamlView = new YamlConfigView(host);
    if (this.messages) {
      this.yamlView.setMessages(this.messages);
    }
    this.yamlView.render({
      overrides: this.currentOverrides,
      onDirty: () => {
        markPendingAutoSave('yamlConfig');
        getOptionsController()?.scheduleAutoSave();
      }
    });
    this.renderViewIfNeeded(this.currentOverrides);
  }

  private loadYamlViewModule(): Promise<typeof import('@ui/domains/yaml-config')> {
    if (!this.yamlViewModulePromise) {
      this.yamlViewModulePromise = import('@ui/domains/yaml-config');
    }
    return this.yamlViewModulePromise;
  }

  private registerFormIntegration(): void {
    const binding: FormSectionHandlers = {
      applySnapshot: (options) => {
        this.applySnapshot(options);
      },
      collectChanges: (previous) => this.collectChanges(previous)
    };
    this.registerManagedFormSection('yamlConfig', binding);
  }

  private applySnapshot(options: StoredOptions): void {
    const overrides = options.yamlConfig ?? null;
    this.currentOverrides = overrides;
    this.updateResolvedSummary();
    this.renderViewIfNeeded(overrides);
  }

  private collectChanges(_previous: StoredOptions | null): Partial<CompleteOptions> {
    const overrides = this.yamlView?.collect() ?? null;
    this.currentOverrides = overrides;
    this.lastRenderedSerialized = JSON.stringify(overrides ?? null);
    this.updateResolvedSummary();
    return { yamlConfig: overrides };
  }

  private disposeView(): void {
    this.yamlView?.destroy();
    this.yamlView = null;
    this.lastRenderedSerialized = null;
  }

  private buildHeader(): HTMLElement {
    this.summaryEl = this.createElement('div', 'text-sm text-base-content/50');
    this.summaryEl.textContent = '…';
    return this.buildSectionHeader({
      title: this.messages?.yamlConfigTitle ?? 'YAML Configuration',
      description:
        this.messages?.yamlConfigHint ??
        this.messages?.yamlConfigNote ??
        'Control which YAML fields are exported for each content type.',
      actions: [this.summaryEl]
    });
  }

  private buildBody(): HTMLElement {
    const pad = this.createElement('div', 'mt-6');
    const host = this.createElement('div', 'space-y-6', {
      id: 'yamlConfigViewHost',
      'data-role': 'yaml-config-view-host'
    });
    pad.append(host);
    return pad;
  }

  private async bootstrapOverrides(): Promise<void> {
    try {
      const overrides = await this.yamlRepository.getOverrides();
      this.currentOverrides = overrides;
      this.updateResolvedSummary();
      this.renderViewIfNeeded(overrides);
    } catch (error) {
      console.warn('[YamlConfigSection] Failed to load YAML overrides from repository:', error);
    }
  }

  private ensureYamlSubscription(): void {
    if (this.unsubscribeYamlRepo) {
      return;
    }
    this.unsubscribeYamlRepo = this.yamlRepository.onChange((overrides) => {
      this.currentOverrides = overrides;
      this.updateResolvedSummary();
      if (this.suppressRepoRender) {
        return;
      }
      this.renderViewIfNeeded(overrides);
    });
  }

  private renderViewIfNeeded(overrides: YamlConfigOverrides | null): void {
    if (!this.yamlView) {
      return;
    }
    const serialized = JSON.stringify(overrides ?? null);
    if (serialized === this.lastRenderedSerialized) {
      return;
    }
    this.suppressRepoRender = true;
    this.yamlView.update(overrides);
    this.suppressRepoRender = false;
    this.lastRenderedSerialized = serialized;
  }

  private updateResolvedSummary(): void {
    if (!this.summaryEl) {
      return;
    }
    try {
      const overrides = this.currentOverrides;
      const summary = CONTENT_TYPE_ORDER.map((type) => {
        const resolved = this.yamlService.resolveConfig(type, overrides, {});
        return `${this.getContentTypeLabel(type)}: ${resolved.fields.length}`;
      }).join(' · ');
      this.summaryEl.textContent =
        summary ||
        (this.messages?.yamlConfigHint ?? 'Manage the YAML fields exported for each content type.');
    } catch (error) {
      console.warn('[YamlConfigSection] Failed to compute YAML preview summary:', error);
    }
  }

  private getContentTypeLabel(type: YamlContentType): string {
    switch (type) {
      case 'article':
        return this.messages?.yamlFieldArticleLabel ?? 'Article';
      case 'clipper':
        return this.messages?.yamlFieldClipperLabel ?? 'Clipper';
      case 'video':
        return this.messages?.yamlFieldVideoLabel ?? 'Video';
      case 'ai_chat':
        return this.messages?.yamlFieldAiLabel ?? 'AI Chat';
      default:
        return type;
    }
  }
}

import type { FragmentClipperOptions } from '@shared/types/options';
import type { FragmentSectionLayoutRefs } from './fragmentSectionLayout';

export interface EventBinding {
  target: EventTarget;
  type: string;
  handler: EventListener;
}

export function createFragmentSectionBindings(refs: FragmentSectionLayoutRefs) {
  return {
    footnoteCheckbox: refs.footnoteCheckbox,
    captureContextCheckbox: refs.captureContextCheckbox,
    modifierToggle: refs.modifierToggle,
    modifierKeyCheckboxes: refs.modifierKeyCheckboxes,
    keyboardShortcutsCheckbox: refs.keyboardShortcutsCheckbox,
    contextLengthInput: refs.contextLengthInput,
    contextModeSelect: refs.contextModeSelect
  };
}

export function bindFragmentSectionEvents(options: {
  refs: FragmentSectionLayoutRefs;
  onValueChanged: EventListener;
  onCaptureContextChange: EventListener;
  onModifierToggleChange: EventListener;
  onContextLengthChange: EventListener;
  onContextLengthBlur: EventListener;
}): EventBinding[] {
  const bindings: EventBinding[] = [];
  const bind = (target: EventTarget | null | undefined, type: string, handler: EventListener) => {
    if (!target) {
      return;
    }
    target.addEventListener(type, handler);
    bindings.push({ target, type, handler });
  };

  bind(options.refs.footnoteCheckbox, 'change', options.onValueChanged);
  bind(options.refs.captureContextCheckbox, 'change', options.onCaptureContextChange);
  bind(options.refs.modifierToggle, 'change', options.onModifierToggleChange);
  options.refs.modifierKeyCheckboxes.forEach((checkbox) => {
    bind(checkbox, 'change', options.onValueChanged);
  });
  bind(options.refs.keyboardShortcutsCheckbox, 'change', options.onValueChanged);
  bind(options.refs.contextLengthInput, 'change', options.onContextLengthChange);
  bind(options.refs.contextLengthInput, 'blur', options.onContextLengthBlur);
  bind(options.refs.contextModeSelect, 'change', options.onValueChanged);

  return bindings;
}

import type { FragmentClipperOptions } from '@shared/types/options';
import { UiInput as DaisyInput } from '@ui/primitives/input';
import { UiCheckbox as DaisyCheckbox } from '@ui/primitives/checkbox';
import { UiSelect as DaisySelect } from '@ui/primitives/select';
import type {
  FragmentLayoutBuilderParams,
  FragmentSectionMessagesLike
} from './fragmentSectionLayoutTypes';

export function buildCheckboxSetting(
  params: FragmentLayoutBuilderParams,
  inputId: string,
  refKey: 'footnoteCheckbox' | 'captureContextCheckbox' | 'keyboardShortcutsCheckbox',
  copy: { label: string; hint: string }
): HTMLElement {
  const { createElement, refs } = params;
  const setting = createElement(
    'div',
    'grid grid-cols-[minmax(0,1fr)] gap-3 py-4 border-t border-base-300 items-start first:border-t-0 first:pt-0'
  );
  const control = createElement('div', 'flex flex-wrap justify-start gap-2');
  const checkboxHost = createElement('div');
  const input = new DaisyCheckbox(checkboxHost).render({ id: inputId, label: copy.label });
  control.append(checkboxHost);
  const hint = createElement('div', 'w-full text-xs text-base-content/60 mt-1');
  hint.textContent = copy.hint;
  setting.append(control, hint);
  refs[refKey] = input;
  return setting;
