  sortRowsByMode
} from './yamlConfigTableModel';
import { validateYamlConfig as validateYamlConfigState } from './yamlConfigTableValidation';
import {
  ARRAY_INPUT_HINT,
  ARRAY_INPUT_PLACEHOLDER,
  CONTENT_TYPES,
  type DomainOverrideEntry,
  type FieldRow,
  type YamlConfigDomainLabels,
  type YamlConfigTableLabels
} from './yamlConfigTableTypes';
import type {
  ControllerState,
  YamlConfigControllerOptions
} from './yamlConfigTableControllerTypes';
import { collectYamlDomainLabels, collectYamlTableLabels } from './yamlConfigTableLabels';

export function createYamlConfigControllerState(
  options: YamlConfigControllerOptions
): ControllerState {
  let tableHost: HTMLElement | null = options.tableHost ?? null;
  let domainHost: HTMLElement | null = options.domainHost ?? null;
  let addButton: HTMLButtonElement | null = options.addFieldButton ?? null;
  const onDirty = options.onDirty ?? null;

  let addButtonHandler: ((event: Event) => void) | null = null;
  let rows: FieldRow[] = [];
  let baseOrder = new Map<string, number>();
  let currentSortMode: YamlContentType | null = null;
  let currentFilterMode: YamlContentType | null = null;
  let defaultGroupExpanded = true;
  let rowErrors = new Map<string, string[]>();
  let globalErrors: string[] = [];
  const advancedOpenRows = new Set<string>();
  let domainEntries: DomainOverrideEntry[] = [];
  let domainErrors = new Map<string, string[]>();
  let validationTimer: number | null = null;

  const markDirty = (): void => {
    if (rowErrors.size || globalErrors.length) {
      return;
    }
    onDirty?.();
  };

  const isFieldAvailableForContentType = (
    fieldName: string,
    contentType: YamlContentType
  ): boolean =>
    getAvailableFieldsForContentType(rows, contentType).some((row) => row.name === fieldName);

  const collectLabels = (): YamlConfigTableLabels =>
    collectYamlTableLabels(tableHost ?? document.getElementById('yamlConfigTable'));

  const collectDomainLabels = (): YamlConfigDomainLabels =>
    collectYamlDomainLabels(domainHost ?? document.getElementById('yamlDomainOverrides'));

  const syncValidationState = (): void => {
    const validation = validateYamlConfigState({
      rows,
      domainEntries,
      tableLabels: collectLabels(),
      domainLabels: collectDomainLabels(),
      isFieldAvailableForContentType
    });
    rowErrors = validation.rowErrors;
    domainErrors = validation.domainErrors;
    globalErrors = validation.globalErrors;
  };

  const moveCustomRow = (rowId: string, offset: number): void => {
    if (currentSortMode || currentFilterMode || offset === 0) {
      return;
    }
    const ordered = getCustomRowsByOrder(rows, baseOrder);
    const index = ordered.findIndex((item) => item.id === rowId);
    if (index === -1) {
      return;
    }
    const targetIndex = index + offset;
    if (targetIndex < 0 || targetIndex >= ordered.length) {
      return;
    }
    const sourceRow = ordered[index];
    const targetRow = ordered[targetIndex];
    const sourceOrder = baseOrder.get(sourceRow.id) ?? 0;
    const targetOrder = baseOrder.get(targetRow.id) ?? 0;
    baseOrder.set(sourceRow.id, targetOrder);
    baseOrder.set(targetRow.id, sourceOrder);
    rows = sortRowsByMode(rows, currentSortMode, baseOrder);
    syncTable();
    markDirty();
  };

  const getCustomMoveAvailability = (rowId: string) => {
    const row = rows.find((item) => item.id === rowId);
    if (!row || row.builtIn || currentSortMode || currentFilterMode) {
      return { canMoveUp: false, canMoveDown: false };
    }
    const ordered = getCustomRowsByOrder(rows, baseOrder);
    const index = ordered.findIndex((item) => item.id === rowId);
    return {
      canMoveUp: index > 0,
      canMoveDown: index !== -1 && index < ordered.length - 1
    };
  };

  const debounceValidation = (): void => {
    if (validationTimer) {
      window.clearTimeout(validationTimer);
    }
    validationTimer = window.setTimeout(() => {
      validationTimer = null;
      syncValidationState();
      syncTable();
    }, 250);
  };

  const renderDomainOverridesIfNeeded = (): void => {
    if (!domainHost) {
      return;
    }
    renderDomainOverrides({
      host: domainHost,
      entries: domainEntries,
      labels: collectDomainLabels(),
      tableLabels: collectLabels(),
      domainErrors,
      getFieldOptionsForEntry: (entry, currentField) =>
        getFieldOptionsForEntry(rows, entry, currentField),
      buildDomainFieldDefinition: (contentType, fieldName) =>
        findFieldDefinition(rows, contentType, fieldName),
      actions: {
        onAddDomainEntry: () => {
          domainEntries.push({
            id: createRowId('domain'),
            domain: '',
            contentType: CONTENT_TYPES[0],
            fields: []
          });
          syncTable();
          debounceValidation();
          markDirty();
        },
        onRemoveDomainEntry: (entryId) => {
          domainEntries = domainEntries.filter((entry) => entry.id !== entryId);
          syncTable();
          debounceValidation();
          markDirty();
        },
        onDomainInput: (entry, value) => {
          entry.domain = value;
          debounceValidation();
        },
        onDomainBlur: () => {
          markDirty();
        },
        onContentTypeChange: (entry, contentType) => {
          entry.contentType = contentType;
          ensureDomainEntryFields(entry, rows, isFieldAvailableForContentType);
          syncTable();
          debounceValidation();
          markDirty();
        },
        onAddDomainField: (entry) => {
          const candidates = getFieldOptionsForEntry(rows, entry);
          if (!candidates.length) {
            return;
          }
          const definition = candidates[0];
          entry.fields.push({
            id: createRowId(`${entry.domain || 'domain'}-${definition.name}`),
            name: definition.name,
            type: definition.type,
            enabled: definition.enabled[entry.contentType] ?? true,
            defaultValue: '',
            valuePath: definition.valuePath ?? ''
          });
          syncTable();
          debounceValidation();
          markDirty();
        },
        onRemoveDomainField: (entryId, fieldId) => {
          const entry = domainEntries.find((item) => item.id === entryId);
          if (!entry) {
            return;
          }
          entry.fields = entry.fields.filter((field) => field.id !== fieldId);
          syncTable();
          debounceValidation();
          markDirty();
        },
        onDomainFieldNameChange: (entry, field, name) => {
          const definition = findFieldDefinition(rows, entry.contentType, name);
          field.name = name;
          field.type = definition?.type ?? 'text';
          field.enabled = definition?.enabled[entry.contentType] ?? true;
          field.defaultValue = '';
          field.valuePath = definition?.valuePath ?? '';
          syncTable();
          debounceValidation();
          markDirty();
        },
        onDomainFieldEnabledChange: (field, checked) => {
          field.enabled = checked;
          debounceValidation();
          markDirty();
        },
        onDomainFieldDefaultInput: (field, value) => {
          field.defaultValue = value;
          debounceValidation();
        },
        onDomainFieldDefaultBlur: (field, value) => {
          const normalized = field.type === 'array' ? formatArrayValue(value) : value;
          field.defaultValue = normalized;
          const active = document.activeElement;
          if (active instanceof HTMLInputElement) {
            active.value = normalized;
          }
          markDirty();
        },
        onDomainFieldValuePathInput: (field, value) => {
          field.valuePath = value;
          debounceValidation();
        },
        onDomainFieldValuePathBlur: (field, value) => {
          const trimmed = value.trim();
          field.valuePath = trimmed ? trimmed : '';
          const active = document.activeElement;
          if (active instanceof HTMLInputElement) {
            active.value = field.valuePath ?? '';
          }
          markDirty();
        }
      }
    });
  };

  const syncTable = (): void => {
    if (!tableHost) {
      return;
    }
    syncValidationState();
    const labels = collectLabels();
    const filteredRows = getFilteredRows(rows, currentFilterMode);
    const table = buildTable({
      labels,
      rows: filteredRows,
      currentFilterMode,
      currentSortMode,
      defaultGroupExpanded,
      advancedOpenRows,
      rowErrors,
      getMoveAvailability: getCustomMoveAvailability,
      onDefaultGroupToggle: (open) => {
        defaultGroupExpanded = open;
      },
      onToggleFilter: (mode) => {
        currentFilterMode = currentFilterMode === mode ? null : mode;
        rows = sortRowsByMode(rows, currentSortMode, baseOrder);
        syncTable();
      },
      onToggleSort: (mode) => {
        currentSortMode = currentSortMode === mode ? null : mode;
        rows = sortRowsByMode(rows, currentSortMode, baseOrder);
        syncTable();
      },
      rowActions: {
        onNameInput: (row, value) => {
          row.name = value;
          debounceValidation();
        },
        onNameBlur: () => {
          rows = sortRowsByMode(rows, currentSortMode, baseOrder);
          syncTable();
          markDirty();
        },
        onTypeChange: (row, type) => {
          row.type = type;
          row.defaultValue = '';
          rows = sortRowsByMode(rows, currentSortMode, baseOrder);
          syncTable();
          markDirty();
        },
        onToggleContentType: (row, contentType, checked) => {
          row.enabled[contentType] = checked;
          rows = sortRowsByMode(rows, currentSortMode, baseOrder);
          syncTable();
          markDirty();
        },
        onAdvancedToggle: (row) => {
          if (advancedOpenRows.has(row.id)) {
            advancedOpenRows.delete(row.id);
          } else {
            advancedOpenRows.add(row.id);
          }
          syncTable();
        },
        onMoveRow: (rowId, offset) => {
          moveCustomRow(rowId, offset);
        },
        onDeleteRow: (row) => {
          baseOrder.delete(row.id);
          rows = rows.filter((item) => item.id !== row.id);
          advancedOpenRows.delete(row.id);
          rows = sortRowsByMode(rows, currentSortMode, baseOrder);
          syncTable();
        },
        onDefaultValueInput: (row, value) => {
          row.defaultValue = value;
          debounceValidation();
        },
        onDefaultValueBlur: (row, value) => {
          const normalized = row.type === 'array' ? formatArrayValue(value) : value;
          row.defaultValue = normalized;
          const active = document.activeElement;
          if (active instanceof HTMLInputElement) {
            active.value = normalized;
          }
          syncTable();
          markDirty();
        },
        onAdvancedValuePathInput: (row, value) => {
          row.valuePath = value;
          debounceValidation();
        },
        onAdvancedValuePathBlur: (row, value) => {
          const trimmed = value.trim();
          if (trimmed) {
            row.valuePath = trimmed;
          } else {
            delete row.valuePath;
          }
          const active = document.activeElement;
          if (active instanceof HTMLInputElement) {
            active.value = row.valuePath ?? '';
          }
          syncTable();
          markDirty();
        }
      }
    });

    const warningsHost = buildGlobalWarnings(globalErrors);
    tableHost.replaceChildren(...(warningsHost ? [warningsHost, table] : [table]));
    renderDomainOverridesIfNeeded();
  };

  const bindAddButton = (): void => {
    const nextButton =
      addButton ??
      (typeof document !== 'undefined'
        ? (document.getElementById('yamlAddFieldBtn') as HTMLButtonElement | null)
        : null);
    addButton?.removeEventListener('click', addButtonHandler as EventListener);
    addButton = nextButton;
    if (!addButton) {
      addButtonHandler = null;
      return;
    }
    addButtonHandler = () => {
      const row: FieldRow = {
        id: createRowId('custom'),
        name: '',
        type: 'text',
        defaultValue: '',
        enabled: createToggleMap(false),
        supported: createToggleMap(true),
        builtIn: false,
        isCustom: true,
        required: false,
        originTypes: new Set()
      };
      baseOrder.set(row.id, nextBaseOrderValue(baseOrder));
      rows = sortRowsByMode([...rows, row], currentSortMode, baseOrder);
      syncTable();
      markDirty();
    };
    addButton.addEventListener('click', addButtonHandler);
  };

  const render = (initial: YamlConfigOverrides | null): void => {
    if (!tableHost && typeof document !== 'undefined') {
      tableHost = document.getElementById('yamlConfigTable');
    }
    if (!domainHost && typeof document !== 'undefined') {
      domainHost = document.getElementById('yamlDomainOverrides');
    }
    if (!addButton && typeof document !== 'undefined') {
      addButton = document.getElementById('yamlAddFieldBtn') as HTMLButtonElement | null;
    }
    if (!tableHost) {
      return;
    }

    rows = buildInitialRows(initial ?? undefined);
    advancedOpenRows.clear();
    rows.forEach((row) => {
      if (row.valuePath?.trim()) {
        advancedOpenRows.add(row.id);
      }
    });
    baseOrder = new Map(rows.map((row, index) => [row.id, index]));
    currentSortMode = null;
    currentFilterMode = null;
    defaultGroupExpanded = true;
    rowErrors = new Map();
    globalErrors = [];
    domainEntries = buildInitialDomainOverrides(initial ?? undefined, rows);
    domainErrors = new Map();
    rows = sortRowsByMode(rows, currentSortMode, baseOrder);
    syncTable();
    bindAddButton();
  };

  const collect = (): YamlConfigOverrides | null => {
    if (!rows.length) {
      return null;
    }
    syncValidationState();
    syncTable();
    if (rowErrors.size || globalErrors.length) {
      throw new Error(globalErrors[0] ?? collectLabels().warnings.unresolvedErrors);
    }
    return collectYamlConfigOverrides({ rows, domainEntries, baseOrder });
  };

  const dispose = (): void => {
    addButton?.removeEventListener('click', addButtonHandler as EventListener);
    if (validationTimer) {
      window.clearTimeout(validationTimer);
    }
    rows = [];
    baseOrder = new Map();
    currentSortMode = null;
    currentFilterMode = null;
    defaultGroupExpanded = true;
    rowErrors = new Map();
    globalErrors = [];
    advancedOpenRows.clear();
    domainEntries = [];
    domainErrors = new Map();
    tableHost = null;
    domainHost = null;
    addButton = null;
    addButtonHandler = null;
    validationTimer = null;
  };

  return { render, collect, dispose };
}

function createRowId(seed: string): string {
  return `yaml-row-${seed}-${Math.random().toString(36).slice(2, 8)}`;
}

import type { YamlContentType } from '@shared/types/yamlConfig';
import { createOptionsButtonElement } from '../../primitives/button';
import { createCheckboxElement } from '../../primitives/checkbox';
import { createInputElement } from '../../primitives/input';
import { createSelectElement } from '../../primitives/select';
import {
  createOptionsActionRow,
  createOptionsHintText,
  createLayoutElement,
  createOptionsPanel
} from '../../primitives/layout';
import {
  ARRAY_INPUT_PLACEHOLDER,
  CONTENT_TYPES,
  type DomainFieldRow,
  type DomainOverrideEntry,
  type FieldRow,
  type YamlConfigDomainLabels,
  type YamlConfigTableLabels
} from './yamlConfigTableTypes';
import { formatArrayValue } from './yamlConfigTableStateModel';
import { buildYamlErrorList } from './yamlConfigTableMessageBuilders';
import {
  buildDomainCard,
  type DomainFieldRendererActions
} from './yamlConfigTableDomainFieldRenderers';

export interface DomainActions extends DomainFieldRendererActions {
  onAddDomainEntry: () => void;
}

export function renderDomainOverrides(args: {
  host: HTMLElement;
  entries: DomainOverrideEntry[];
  labels: YamlConfigDomainLabels;
  tableLabels: YamlConfigTableLabels;
  domainErrors: Map<string, string[]>;
  getFieldOptionsForEntry: (
    entry: DomainOverrideEntry,
    currentField?: DomainFieldRow
  ) => FieldRow[];
  buildDomainFieldDefinition: (
    contentType: YamlContentType,
    fieldName: string
  ) => FieldRow | undefined;
  actions: DomainActions;
}): void {
  const {
    host,
    entries,
    labels,
    tableLabels,
    domainErrors,
    getFieldOptionsForEntry,
    buildDomainFieldDefinition,
    actions
  } = args;
  const wrapper = createLayoutElement({ className: 'aobx-domain' });

  const header = createOptionsActionRow({ className: 'aobx-domain__header pt-0' });
  const title = createLayoutElement({ tag: 'h3' });
  title.textContent = labels.title;
  const addButton = createOptionsButtonElement({
    label: labels.addRule,
    variant: 'primary',
    size: 'sm',
    className: 'aobx-btn aobx-domain__add-btn'
  });
  addButton.addEventListener('click', actions.onAddDomainEntry);
  header.append(title, addButton);

  const list = createLayoutElement({ className: 'aobx-domain__list' });
  if (!entries.length) {
    const empty = createLayoutElement({
      className: 'aobx-domain__empty',
      textContent: labels.empty
    });
    list.append(empty);
  } else {
    entries.forEach((entry) => {
      list.append(
        buildDomainCard({
          entry,
          labels,
          typeLabels: Object.fromEntries(
            CONTENT_TYPES.map((type) => [type, tableLabels.typeLabels[type] ?? type])
          ) as Record<YamlContentType, string>,
          errors: domainErrors.get(entry.id) ?? [],
          getFieldOptionsForEntry,
          actions,
          buildErrorList: (nextErrors) => buildYamlErrorList('aobx-domain__errors', nextErrors)
        })
      );
    });
  }

  const hint = createOptionsHintText({
    className: 'aobx-domain__hint',
    text: labels.hint
  });
  wrapper.append(header, list, hint);
  host.replaceChildren(wrapper);
}

import type { YamlContentType } from '@shared/types/yamlConfig';
import { createOptionsButtonElement } from '../../primitives/button';
import {
  createOptionsActionRow,
  createLayoutElement,
  createOptionsPanel
} from '../../primitives/layout';
import { CONTENT_TYPES, type FieldRow, type YamlConfigTableLabels } from './yamlConfigTableTypes';
import {
  buildYamlErrorList,
  buildYamlTableRow,
  renderDomainOverrides,
  type DomainActions,
  type RowActions
} from './yamlConfigTableSharedRenderers';
export { renderDomainOverrides } from './yamlConfigTableSharedRenderers';

export function renderFilters(args: {
  labels: YamlConfigTableLabels;
  currentFilterMode: YamlContentType | null;
  onToggleFilter: (mode: YamlContentType | null) => void;
}): HTMLElement {
  const { labels, currentFilterMode, onToggleFilter } = args;
  const container = createOptionsActionRow({ className: 'mb-4 flex flex-wrap gap-2 pt-0' });
  const filters: Array<{ mode: YamlContentType | null; label: string }> = [
    { mode: null, label: labels.filterAll },
    { mode: 'article', label: labels.article },
    { mode: 'clipper', label: labels.clipper },
    { mode: 'video', label: labels.video },
    { mode: 'ai_chat', label: labels.ai }
  ];

  filters.forEach(({ mode, label }) => {
    const button = createOptionsButtonElement({
      label,
      size: 'xs',
      className:
        'rounded-full bg-base-200 text-base-content/60 border border-base-300 hover:bg-base-300 hover:text-base-content hover:border-base-content'
    });
    if (currentFilterMode === mode) {
      button.classList.add('bg-accent/10', 'text-accent', 'border-accent/20');
      button.classList.remove('bg-base-200', 'text-base-content/60', 'border-base-300');
    }
    button.addEventListener('click', () => onToggleFilter(mode));
    container.append(button);
  });

  return container;
}

export function buildHeader(args: {
  labels: YamlConfigTableLabels;
  currentSortMode: YamlContentType | null;
  onToggleSort: (mode: YamlContentType) => void;
}): HTMLElement {
  const { labels, currentSortMode, onToggleSort } = args;
  const header = createLayoutElement({
    className:
      'grid grid-cols-[minmax(120px,1.5fr)_100px_repeat(4,60px)_minmax(120px,1fr)_80px] gap-2 border-b border-base-300 bg-base-200 p-3 text-xs font-medium uppercase tracking-wider text-base-content/60'
  });

  const columns: Array<{ key: string; label: string; mode?: YamlContentType }> = [
    { key: 'field', label: labels.field },
    { key: 'type', label: labels.type },
    { key: 'article', label: labels.article, mode: 'article' },
    { key: 'clipper', label: labels.clipper, mode: 'clipper' },
    { key: 'video', label: labels.video, mode: 'video' },
    { key: 'ai', label: labels.ai, mode: 'ai_chat' },
    { key: 'defaultValue', label: labels.defaultValue },
    { key: 'actions', label: labels.actions }
  ];

  columns.forEach((column) => {
    const span = document.createElement('span');
    const mode = column.mode;
    if (mode) {
      const button = createOptionsButtonElement({
        label: column.label,
        variant: 'ghost',
        size: 'sm',
        className: 'gap-1 hover:text-text'
      });
      if (currentSortMode === mode) {
        button.classList.add('text-accent', 'font-bold');
      }
      button.addEventListener('click', () => onToggleSort(mode));
      span.append(button);
    } else {
      span.textContent = column.label;
    }
    header.append(span);
  });

  return header;
}

export function buildTable(args: {
  labels: YamlConfigTableLabels;
  rows: FieldRow[];
  currentFilterMode: YamlContentType | null;
  currentSortMode: YamlContentType | null;
  defaultGroupExpanded: boolean;
  advancedOpenRows: Set<string>;
  rowErrors: Map<string, string[]>;
  getMoveAvailability: (rowId: string) => { canMoveUp: boolean; canMoveDown: boolean };
  onDefaultGroupToggle: (open: boolean) => void;
  onToggleFilter: (mode: YamlContentType | null) => void;
  onToggleSort: (mode: YamlContentType) => void;
  rowActions: RowActions;
}): HTMLElement {
  const {
    labels,
    rows,
    currentFilterMode,
    currentSortMode,
    defaultGroupExpanded,
    advancedOpenRows,
    rowErrors,
    getMoveAvailability,
    onDefaultGroupToggle,
    onToggleFilter,
    onToggleSort,
    rowActions
  } = args;

  const root = createOptionsPanel({
    className:
      'aobx-table min-w-[800px] w-full overflow-hidden rounded-lg border border-base-300 bg-base-100 text-sm shadow-sm'
  });
  root.append(
    renderFilters({
      labels,
      currentFilterMode,
      onToggleFilter
    })
  );
  root.append(buildHeader({ labels, currentSortMode, onToggleSort }));

  const builtInRows = rows.filter((row) => row.builtIn);
  const customRows = rows.filter((row) => !row.builtIn);
  const firstBuiltInIndex = rows.findIndex((row) => row.builtIn);
  const firstCustomIndex = rows.findIndex((row) => !row.builtIn);
  const order: Array<'builtIn' | 'custom'> = [];
  if (builtInRows.length) {
    order.push('builtIn');
  }
  if (customRows.length) {
    order.push('custom');
  }
  if (currentSortMode && builtInRows.length && customRows.length && firstCustomIndex !== -1) {
    if (firstBuiltInIndex === -1 || firstCustomIndex < firstBuiltInIndex) {
      order.sort((value) => (value === 'custom' ? -1 : 1));
    }
  }

  order.forEach((groupType) => {
    if (groupType === 'builtIn') {
      const group = createLayoutElement({ tag: 'details', className: 'group' });
      group.open = defaultGroupExpanded;
      group.addEventListener('toggle', () => onDefaultGroupToggle(group.open));

      const summary = createLayoutElement({
        tag: 'summary',
        className:
          'flex cursor-pointer select-none items-center gap-2 bg-base-200 px-3 py-2 font-medium text-base-content/60 transition-colors hover:text-base-content marker:text-base-content/50'
      });
      const total = builtInRows.length;
      const enabled = currentFilterMode
        ? builtInRows.filter((row) => row.enabled[currentFilterMode]).length
        : builtInRows.filter((row) => CONTENT_TYPES.some((mode) => row.enabled[mode])).length;
      summary.textContent = `${labels.defaultGroup} (${enabled}/${total})`;
      group.append(summary);

      const body = createLayoutElement({ className: 'divide-y divide-base-300' });
      builtInRows.forEach((row) =>
        body.append(
          buildYamlTableRow({
            row,
            labels,
            advancedOpenRows,
            rowErrors,
            getMoveAvailability,
            actions: rowActions
          })
        )
      );
      group.append(body);
      root.append(group);
      return;
    }

    const container = createLayoutElement({ className: 'border-t border-base-300' });
    const customHeader = createLayoutElement({
      className: 'border-b border-base-300 bg-base-200 px-3 py-2 font-medium text-base-content/60'
    });
    const total = customRows.length;
    const enabled = currentFilterMode
      ? customRows.filter((row) => row.enabled[currentFilterMode]).length
      : customRows.filter((row) => CONTENT_TYPES.some((mode) => row.enabled[mode])).length;
    customHeader.textContent = `${labels.customGroup} (${enabled}/${total})`;
    container.append(customHeader);
    customRows.forEach((row) =>
      container.append(
        buildYamlTableRow({
          row,
          labels,
          advancedOpenRows,
          rowErrors,
          getMoveAvailability,
          actions: rowActions
        })
      )
    );
    root.append(container);
  });

  return root;
}

export function buildGlobalWarnings(globalErrors: string[]): HTMLElement | null {
  if (!globalErrors.length) {
    return null;
  }
  const container = createOptionsPanel({
    className: 'alert alert-error aobx-table__global-errors p-3 text-sm',
    attributes: { role: 'alert' }
  });
  globalErrors.forEach((message) => {
    container.append(createLayoutElement({ textContent: message }));
  });
  return container;
}

import type { YamlContentType, YamlFieldType } from '@shared/types/yamlConfig';
import { createCheckboxElement } from '../../primitives/checkbox';
import { createInputElement } from '../../primitives/input';
import { createSelectElement } from '../../primitives/select';
import { createLayoutElement } from '../../primitives/layout';
