  });

  it('suppresses benign support-prompt send failures', async () => {
    processClipPayloadMock.mockResolvedValue({
      filePath: 'Articles/foo.md',
      vaultName: 'Secondary Vault',
      restVault: 'Secondary',
      destination: 'vault',
