      'aria-label',
      'commentLabel'
    );

    window.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));
    await resultPromise;

    for (const handle of [...textHandles, ...attrHandles]) {
      expect(handle.dispose).toHaveBeenCalled();
    }
