    callbacks.onFinish();
    await vi.waitFor(() => {
      expect(context.dispatchClipResult).toHaveBeenCalledTimes(1);
    });
    expect(context.showSupportProgress).toHaveBeenCalledWith({
      value: 10,
      label: '正在准备阅读导出'
