import type {
  ClipPromptRequest,
  ClipPromptResponse
} from '@content/clipper/application/clipPromptGateway';
import * as selectionExtractor from '@content/extractors/selectionExtractor';
import type { SelectionClipResult } from '@content/extractors/selectionExtractor';
import {
  __resetContentSessionRegistryForTests,
  registerReaderSession,
  registerVideoSession
} from '@content/runtime/contentSessionRegistry';

const extractSelectionClipMock = vi.spyOn(selectionExtractor, 'extractSelectionClip');
let promptMock: ReturnType<typeof vi.fn<[ClipPromptRequest], Promise<ClipPromptResponse>>>;
const platformHarness: TestPlatformHarness = testPlatformHarness;

describe('content selectionController service', () => {
  beforeEach(async () => {
    promptMock = vi.fn<[ClipPromptRequest], Promise<ClipPromptResponse>>();
    extractSelectionClipMock.mockReset();
    await platformHarness.storage.sync.clear();
    await platformHarness.storage.sync.set('options', {});
    __resetContentSessionRegistryForTests(document);
  });

  afterEach(() => {
    vi.clearAllMocks();
    document.body.innerHTML = '';
    __resetContentSessionRegistryForTests(document);
  });

  function createSelection(text: string, html = `<p>${text}</p>`): Selection {
    const template = document.createElement('template');
    template.innerHTML = html;
    const fragment = template.content;
    const range = document.createRange();
    const textNode = document.createTextNode(text);
    fragment.appendChild(textNode);
    range.setStart(textNode, 0);
    range.setEnd(textNode, text.length);

    const selection = mkSelection({
      rangeCount: 1,
      isCollapsed: false,
      anchorNode: fragment.firstChild,
      focusNode: fragment.firstChild,
      anchorOffset: 0,
      focusOffset: text.length,
      toString: () => text,
      getRangeAt: () => range,
      removeAllRanges: vi.fn()
    });

    return selection;
  }

  async function createController() {
    const module = await import('@content/clipper/services/selectionController');
    const readerSessionFactory = vi.fn().mockReturnValue({
      ingestExternalHighlight: vi.fn(),
      start: vi.fn()
    });
    const videoSessionFactory = vi.fn().mockReturnValue({
      start: vi.fn(),
      ingestTextCapture: vi.fn()
    });
    const controller = module.createSelectionController({
      prompt: {
        requestSelectionAction: promptMock
      },
      optionsRepository: {
        get: vi.fn().mockResolvedValue({
          fragmentClipper: {
            useFootnoteFormat: false,
            captureContext: true,
            contextLength: 200,
            contextMode: 'chars',
            selectionModifierEnabled: false,
            selectionModifierKeys: []
          }
        }),
        set: vi.fn(),
        onChange: vi.fn().mockReturnValue(() => {})
      },
      createReaderSession: readerSessionFactory,
      createVideoSession: videoSessionFactory
    });
    return { controller, readerSessionFactory, videoSessionFactory };
  }

  it('returns null when dialog is cancelled', async () => {
    promptMock.mockResolvedValue({ action: 'cancel', comment: '' });
    const selection = createSelection('Selected text');

    const { controller } = await createController();
    const result = await controller.handleSelectionClip(document, 'https://example.com', selection);

    expect(result).toBeNull();
    expect(extractSelectionClipMock).not.toHaveBeenCalled();
  });

  it('extracts selection clip with merged configuration when confirmed', async () => {
    promptMock.mockResolvedValue({ action: 'clip', comment: 'note' });
    const selection = createSelection('Selected text');

    const clipResult: SelectionClipResult = {
      type: 'clipper',
      title: 'note',
      pageTitle: 'note',
      markdown: '# note',
      meta: {
        url: 'https://example.com/',
        fragmentUrl: 'https://example.com/#:~:text=Selected%20text',
        domain: 'example.com',
        clippedAtISO: '1970-01-01T00:00:00.000Z',
        hasComment: true,
        selectedTextPreview: 'Selected text',
        sourceUrl: 'https://example.com',
        resolvedUrl: 'https://example.com/'
      }
    };
    extractSelectionClipMock.mockResolvedValue(clipResult);

    await testPlatformHarness.storage.sync.set('options', {
      fragmentClipper: {
        useFootnoteFormat: false,
        captureContext: true,
        contextLength: 50,
        contextMode: 'sentences'
      }
    });

    const { controller } = await createController();
    const result = await controller.handleSelectionClip(document, 'https://example.com', selection);

    expect(result).toEqual(clipResult);
    expect(extractSelectionClipMock).toHaveBeenCalledTimes(1);
    const args = extractSelectionClipMock.mock.calls[0][0];
    expect(args.userComment).toBe('note');
    expect(args.config).toEqual({
      useFootnoteFormat: false,
      captureContext: true,
      contextLength: 200,
      contextMode: 'chars',
      selectionModifierEnabled: false,
      selectionModifierKeys: [],
      keyboardShortcutsEnabled: true
    });
  });

  it('passes the selected export destination into confirmed selection clips', async () => {
    promptMock.mockResolvedValue({
      action: 'clip',
      comment: '',
      destination: { kind: 'downloads' }
    });
    const selection = createSelection('Selected text');
    const clipResult: SelectionClipResult = {
      type: 'clipper',
      title: 'note',
      pageTitle: 'note',
      markdown: '# note',
      meta: {
        url: 'https://example.com/',
        fragmentUrl: 'https://example.com/#:~:text=Selected%20text',
        domain: 'example.com',
        clippedAtISO: '1970-01-01T00:00:00.000Z',
        hasComment: false,
        selectedTextPreview: 'Selected text',
        sourceUrl: 'https://example.com',
        resolvedUrl: 'https://example.com/'
      }
    };
    extractSelectionClipMock.mockResolvedValue(clipResult);

    const { controller } = await createController();
    const result = await controller.handleSelectionClip(document, 'https://example.com', selection);

    expect(result?.meta).toMatchObject({
      exportDestination: { kind: 'downloads' }
    });
  });

  it('throws when selection is empty', async () => {
    promptMock.mockResolvedValue({ action: 'clip', comment: '' });
    const selection = createSelection('   ');

    const { controller } = await createController();
    await expect(
      controller.handleSelectionClip(document, 'https://example.com', selection)
    ).rejects.toThrow('Selected text is empty');
  });

  it('throws when there are no selection ranges', async () => {
    promptMock.mockResolvedValue({ action: 'clip', comment: '' });
    const selection = mkSelection({
      rangeCount: 0,
      isCollapsed: true,
      toString: () => '',
      removeAllRanges: vi.fn(),
      getRangeAt: () => {
        throw new Error('no range');
      }
    });

    const { controller } = await createController();
    await expect(
      controller.handleSelectionClip(document, 'https://example.com', selection)
    ).rejects.toThrow('No text selected');
  });

  it('reuses registered reader session without falling back to window globals', async () => {
    promptMock.mockResolvedValue({ action: 'reader', comment: 'note' });
    const selection = createSelection('Selected text');
    const existingSession = {
      ingestExternalHighlight: vi.fn(),
      start: vi.fn()
    };
    registerReaderSession(existingSession, document);

    const { controller, readerSessionFactory } = await createController();
    const result = await controller.handleSelectionClip(document, 'https://example.com', selection);

    expect(result).toBeNull();
    expect(existingSession.ingestExternalHighlight).toHaveBeenCalledTimes(1);
    expect(readerSessionFactory).not.toHaveBeenCalled();
  });

  it('passes the selected export destination into a new reader session', async () => {
    promptMock.mockResolvedValue({
      action: 'reader',
      comment: 'note',
      destination: { kind: 'vault', vaultId: 'research' }
    });
    const selection = createSelection('Selected text');

    const { controller, readerSessionFactory } = await createController();
    await controller.handleSelectionClip(document, 'https://example.com', selection);

    const readerSession = readerSessionFactory.mock.results[0]?.value;
    expect(readerSession.start).toHaveBeenCalledWith(
      expect.objectContaining({
        comment: 'note',
        destination: { kind: 'vault', vaultId: 'research' }
      })
    );
  });

  it('reuses registered video session for selection clip', async () => {
    const selection = createSelection('Selected text');
    const existingSession = {
      start: vi.fn(),
      ingestTextCapture: vi.fn()
    };
    registerVideoSession(existingSession, document);

    const { controller, videoSessionFactory } = await createController();
    await controller.handleVideoSelectionClip(document, 'https://example.com/watch?v=1', selection);

    expect(existingSession.ingestTextCapture).toHaveBeenCalledTimes(1);
    expect(videoSessionFactory).not.toHaveBeenCalled();
  });
});

/* @vitest-environment jsdom */

import { beforeEach, describe, expect, it, vi } from 'vitest';
import type { Mock } from 'vitest';
import { BilibiliVideoPlatform } from '@content/video/platforms/bilibiliPlatform';
import {
  isBilibiliCommentRegionNode,
  isBilibiliDanmakuNode
} from '@content/video/platforms/bilibiliPlatformObserver';
import {
  flattenBilibiliContentNode,
  parseBilibiliDataContent,
  resolveBilibiliRichTextContainer,
  serializeBilibiliRichTextFragment
} from '@content/video/platforms/bilibiliRichText';
import type { PlatformSelectionInput, VideoPlatformContext } from '@content/video/platforms';

interface VideoPlatformContextMocks {
  highlightSelection: Mock<[Range, string, string], string | undefined>;
  decorateHighlight: Mock<[HTMLElement], void>;
  scheduleFragmentHighlightRestore: Mock<[], void>;
  getElementByIdDeep: Mock<[string], HTMLElement | null>;
  querySelectorDeep: Mock<[string], Element | null>;
  observeWithFragmentObserver: Mock<[Node, MutationObserverInit], void>;
  registerShadowSelectionBridge: Mock<[ShadowRoot], void>;
  ensureHighlightStyles: Mock<[ShadowRoot], void>;
}

type VideoPlatformContextWithMocks = VideoPlatformContext & {
  __mocks: VideoPlatformContextMocks;
};

function createContext(doc: Document): VideoPlatformContextWithMocks {
  const mocks: VideoPlatformContextMocks = {
    highlightSelection: vi.fn<[Range, string, string], string | undefined>(() => 'wrapper-1'),
    decorateHighlight: vi.fn<[HTMLElement], void>(),
    scheduleFragmentHighlightRestore: vi.fn<[], void>(),
    getElementByIdDeep: vi.fn<[string], HTMLElement | null>(() => null),
    querySelectorDeep: vi.fn<[string], Element | null>(() => null),
    observeWithFragmentObserver: vi.fn<[Node, MutationObserverInit], void>(),
    registerShadowSelectionBridge: vi.fn<[ShadowRoot], void>(),
    ensureHighlightStyles: vi.fn<[ShadowRoot], void>()
  };

  return {
    doc,
    ...mocks,
    querySelectorDeep: <T extends Element>(selector: string): T | null =>
      mocks.querySelectorDeep(selector) as T | null,
    __mocks: mocks
  };
}

function withScheduledRestore(
  context: VideoPlatformContextWithMocks,
  scheduleRestore: VideoPlatformContextMocks['scheduleFragmentHighlightRestore']
): VideoPlatformContextWithMocks {
  context.scheduleFragmentHighlightRestore = scheduleRestore;
  context.__mocks.scheduleFragmentHighlightRestore = scheduleRestore;
  return context;
}

describe('BilibiliVideoPlatform', () => {
  beforeEach(() => {
    document.body.innerHTML = '';
    document.title = '';
    vi.useRealTimers();
  });

  it('activates on bilibili hosts and formats bilibili titles', () => {
    const platform = new BilibiliVideoPlatform(createContext(document));

    expect(
      platform.shouldActivate({ location: { hostname: 'www.bilibili.com' } } as Document)
    ).toBe(true);
    expect(platform.formatVideoTitle('测试视频___哔哩哔哩_bilibili')).toBe('测试视频');
    expect(platform.formatVideoTitle('   ')).toBeNull();
  });

  it('builds timestamp urls with active episode fallback', () => {
    document.body.innerHTML =
      '<div class="video-episode-card__entry is-active" data-index="2"></div>';
    const platform = new BilibiliVideoPlatform(createContext(document));

    const url = platform.buildTimestampUrl(135, {
      canonicalUrl: 'https://www.bilibili.com/video/BV1xx411c7mD',
      currentUrl: document.location.href,
      videoId: 'BV1xx411c7mD'
    });

    expect(url).toBe('https://www.bilibili.com/video/BV1xx411c7mD?t=135&p=3');
  });

  it('falls back to rich text range extraction when selected text/html are missing', () => {
    const host = document.createElement('bili-rich-text');
    const shadowRoot = host.attachShadow({ mode: 'open' });
    const content = document.createElement('div');
    content.className = 'rich-text-content';
    content.innerHTML = '<span>Hello</span><span> world</span>';
    shadowRoot.appendChild(content);
    document.body.appendChild(host);

    const range = document.createRange();
    const firstText = content.querySelector('span')?.firstChild;
    const lastText = content.querySelectorAll('span')[1]?.firstChild;
    if (!firstText || !lastText) {
      throw new Error('Failed to build Bilibili rich text fixture');
    }
    range.setStart(firstText, 0);
    range.setEnd(lastText, lastText.textContent?.length ?? 0);

    const platform = new BilibiliVideoPlatform(createContext(document));
    const result = platform.resolveSelection({
      range,
      selectedText: '',
      selectedHtml: ''
    } as PlatformSelectionInput);

    expect(result?.text).toBe('Hello world');
    expect(result?.html).toContain('Hello');
    expect(result?.range?.toString()).toBe('Hello world');
  });

  it('extracts selection from event composed path when range is absent', () => {
    const host = document.createElement('bili-rich-text');
    const shadowRoot = host.attachShadow({ mode: 'open' });
    const content = document.createElement('div');
    content.className = 'rich-text-content';
    content.textContent = 'Event fallback text';
    shadowRoot.appendChild(content);
    document.body.appendChild(host);

    const event = new MouseEvent('mouseup', { bubbles: true });
    Object.defineProperty(event, 'composedPath', {
      configurable: true,
      value: () => [content, shadowRoot, host, document.body, document, window]
    });

    const platform = new BilibiliVideoPlatform(createContext(document));
    const result = platform.resolveSelection({
      range: null,
      selectedText: '',
      selectedHtml: '',
      event
    } as PlatformSelectionInput);

    expect(result?.text).toBe('Event fallback text');
    expect(result?.html).toContain('Event fallback text');
    expect(result?.range?.toString()).toBe('Event fallback text');
  });

  it('schedules restore when comment hosts are added through mutations', () => {
    vi.useFakeTimers();
    const scheduleRestore = vi.fn();
    const context = withScheduledRestore(createContext(document), scheduleRestore);
    const platform = new BilibiliVideoPlatform(context);

    platform.handleMutations([
      {
        type: 'childList',
        addedNodes: [document.createElement('bili-comment-renderer')],
        removedNodes: [],
        target: document.body,
        attributeName: null,
        attributeNamespace: null,
        nextSibling: null,
        oldValue: null,
        previousSibling: null
      } as unknown as MutationRecord
    ]);

    expect(scheduleRestore).not.toHaveBeenCalled();
    vi.advanceTimersByTime(110);
    expect(scheduleRestore).toHaveBeenCalledTimes(1);
  });

  it('parses structured data-content JSON and preserves mentions', () => {
    const host = document.createElement('bili-rich-text');
    host.setAttribute(
      'data-content',
      JSON.stringify({
        rich_text_nodes: [{ text: 'Hello ' }, { type: 'at', name: 'Alice' }, { text: ' world' }]
      })
    );
    document.body.appendChild(host);

    const event = new MouseEvent('mouseup', { bubbles: true });
    Object.defineProperty(event, 'composedPath', {
      configurable: true,
      value: () => [host, document.body, document, window]
    });

    const platform = new BilibiliVideoPlatform(createContext(document));
    const result = platform.resolveSelection({
      range: null,
      selectedText: '',
      selectedHtml: '',
      event
    } as PlatformSelectionInput);

    expect(result?.text).toBe('Hello @Alice world');
    expect(result?.html).toContain('Hello @Alice world');
  });

  it('finds text ranges inside nested shadow roots and strips emoji markers for matching', () => {
    const commentHost = document.createElement('bili-comment-renderer');
    const commentRoot = commentHost.attachShadow({ mode: 'open' });
    const richTextHost = document.createElement('bili-rich-text');
    richTextHost.setAttribute('data-content', '[doge] nested text');
    const richTextRoot = richTextHost.attachShadow({ mode: 'open' });
    const content = document.createElement('div');
    content.className = 'rich-text-content';
    content.textContent = '[doge] nested text';
    richTextRoot.appendChild(content);
    commentRoot.appendChild(richTextHost);
    document.body.appendChild(commentHost);

    const platform = new BilibiliVideoPlatform(createContext(document));
    const range = platform.findTextRange('nested text');

    expect(range?.toString()).toContain('nested text');
  });

  it('observes comment shadow roots and delegates highlight/restore through base behavior', () => {
    const context = createContext(document);
    const platform = new BilibiliVideoPlatform(context);

    const commentHost = document.createElement('bili-comment-renderer');
    const commentRoot = commentHost.attachShadow({ mode: 'open' });
    const richTextHost = document.createElement('bili-rich-text');
    const richTextRoot = richTextHost.attachShadow({ mode: 'open' });
    const content = document.createElement('div');
    content.className = 'rich-text-content';
    content.textContent = 'Observed text';
    richTextRoot.appendChild(content);
    commentRoot.appendChild(richTextHost);
    document.body.appendChild(commentHost);

    const observer = new MutationObserver(() => undefined);
    platform.observeDomChanges(observer);

    const range = document.createRange();
    const textNode = content.firstChild;
    if (!textNode) {
      throw new Error('Expected shadow text node');
    }
    range.setStart(textNode, 0);
    range.setEnd(textNode, 'Observed'.length);

    expect(platform.highlight(range, 'capture-1', 'https://example.com/#:~:text=Observed')).toBe(
      'wrapper-1'
    );
    const {
      ensureHighlightStyles,
      registerShadowSelectionBridge,
      observeWithFragmentObserver,
      highlightSelection
    } = context.__mocks;
    expect(ensureHighlightStyles).toHaveBeenCalledWith(commentRoot);
    expect(registerShadowSelectionBridge).toHaveBeenCalledWith(commentRoot);
    expect(observeWithFragmentObserver).toHaveBeenCalledWith(commentRoot, {
      childList: true,
      subtree: true
    });
    expect(ensureHighlightStyles.mock.calls.length).toBeGreaterThanOrEqual(1);
    expect(highlightSelection).toHaveBeenCalled();

    const existing = document.createElement('mark');
    existing.id = 'existing-wrapper';
    context.__mocks.getElementByIdDeep.mockReturnValue(existing);
