describe('SentryErrorReporter', () => {
  const fetchMock = vi.fn();

  beforeEach(() => {
    vi.resetModules();
    vi.clearAllMocks();
    vi.stubGlobal('fetch', fetchMock);
    getServiceMock.mockReturnValue({
      runtime: {
        getManifest: () => ({ version: '9.9.9' })
      }
    });
  });

  it('does nothing when disabled', async () => {
    const { SentryErrorReporter } = await import('../../../../../src/shared/errors/analytics/sentryReporter');
    const reporter = new SentryErrorReporter({
      dsn: 'https://public@example.ingest.sentry.io/123456',
      enabled: false
    });

    await reporter.report({
      code: 'TEST',
      domain: 'background',
      severity: ErrorSeverity.ERROR,
      recoverable: false,
      message: 'boom',
      timestamp: Date.now()
    });

    expect(fetchMock).not.toHaveBeenCalled();
  });

  it('sends sanitized envelope payloads to sentry', async () => {
    fetchMock.mockResolvedValue({ ok: true });

    const { SentryErrorReporter } = await import('../../../../../src/shared/errors/analytics/sentryReporter');
    const reporter = new SentryErrorReporter({
      dsn: 'https://public@example.ingest.sentry.io/123456',
      enabled: true,
      environment: 'test',
      release: '1.2.3'
    });

    await reporter.report({
      code: 'REST_FAIL',
      domain: 'rest',
      severity: ErrorSeverity.CRITICAL,
      recoverable: true,
      message: 'write failed',
      timestamp: 1700000000000,
      context: {
        vault: 'Main'
      }
    });

    expect(sanitizeErrorForAnalyticsMock).toHaveBeenCalled();
    expect(fetchMock).toHaveBeenCalledWith(
      'https://example.ingest.sentry.io/api/123456/envelope/',
      expect.objectContaining({
        method: 'POST',
        headers: expect.objectContaining({
          'Content-Type': 'text/plain;charset=UTF-8'
        }),
        body: expect.stringContaining('"error_code":"REST_FAIL"')
      })
    );
  });

  it('swallows failed sentry requests', async () => {
    const warnSpy = vi.spyOn(console, 'warn').mockImplementation(() => undefined);
    fetchMock.mockResolvedValue({ ok: false, status: 500, statusText: 'Broken' });

    const { SentryErrorReporter } = await import('../../../../../src/shared/errors/analytics/sentryReporter');
    const reporter = new SentryErrorReporter({
      dsn: 'https://public@example.ingest.sentry.io/123456',
      enabled: true
    });

    await reporter.report({
      code: 'FAIL',
      domain: 'content',
      severity: ErrorSeverity.ERROR,
      recoverable: false,
      message: 'oops',
      timestamp: Date.now()
    });

    expect(warnSpy).toHaveBeenCalledWith('[Sentry Reporter] Failed to report error:', expect.any(Error));
    warnSpy.mockRestore();
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import type { StorageAreaService, StorageService } from '../../../../src/platform/interfaces/storage';

function createStorageService(): StorageService {
  const localStore = new Map<string, unknown>();
  const local: StorageAreaService = {
    get: vi.fn(async <T,>(key: string) => localStore.get(key) as T | undefined) as StorageAreaService['get'],
    set: vi.fn(async <T,>(key: string, value: T) => {
      localStore.set(key, value);
    }) as StorageAreaService['set'],
    getMany: vi.fn(async <T,>() => ({} as Record<string, T | undefined>)) as StorageAreaService['getMany'],
    setMany: vi.fn(async <T,>(_entries: Record<string, T>) => undefined) as StorageAreaService['setMany'],
    remove: vi.fn(async (key: string | string[]) => {
      const keys = Array.isArray(key) ? key : [key];
      keys.forEach((entry) => localStore.delete(entry));
    }) as StorageAreaService['remove'],
    clear: vi.fn(async () => {
      localStore.clear();
    }) as StorageAreaService['clear'],
    watchKey: vi.fn(() => () => undefined) as StorageAreaService['watchKey'],
    watchAll: vi.fn(() => () => undefined) as StorageAreaService['watchAll']
  };

  const sync: StorageAreaService = {
    get: vi.fn(async <T,>() => undefined as T | undefined) as StorageAreaService['get'],
    set: vi.fn(async <T,>(_key: string, _value: T) => undefined) as StorageAreaService['set'],
    getMany: vi.fn(async <T,>() => ({} as Record<string, T | undefined>)) as StorageAreaService['getMany'],
    setMany: vi.fn(async <T,>(_entries: Record<string, T>) => undefined) as StorageAreaService['setMany'],
    remove: vi.fn(async () => undefined) as StorageAreaService['remove'],
    clear: vi.fn(async () => undefined) as StorageAreaService['clear'],
    watchKey: vi.fn(() => () => undefined) as StorageAreaService['watchKey'],
    watchAll: vi.fn(() => () => undefined) as StorageAreaService['watchAll']
  };

  return {
    local,
    sync
  };
}

